const raw = $input.first().json || {};
const input = Array.isArray(raw) ? (raw[0] || {}) : raw;

function cleanString(value) {
  if (value === undefined || value === null) return "";
  return String(value).trim();
}

function onlyDigits(value) {
  return cleanString(value).replace(/\D/g, "");
}

function firstFilled(...values) {
  for (const value of values) {
    const text = cleanString(value);
    if (text) return text;
  }
  return "";
}

function toBool(value, fallback = false) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1) return true;
  if (value === 0) return false;

  const text = cleanString(value).toLowerCase();

  if (["true", "sim", "yes", "1"].includes(text)) return true;
  if (["false", "nao", "não", "no", "0"].includes(text)) return false;

  return fallback;
}

function safeNumber(value, fallback) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function normalizeArray(value) {
  return Array.isArray(value) ? value : [];
}

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function removeSensitivePixLikeData(obj) {
  if (!isObject(obj)) return {};

  const forbiddenKeys = [
    "pix",
    "chave_pix",
    "chavepix",
    "cnpj",
    "recebedor",
    "banco",
    "agencia",
    "agência",
    "conta",
    "dados_bancarios",
    "dados_bancários"
  ];

  const out = {};

  for (const [key, value] of Object.entries(obj)) {
    const keyNorm = key
      .toLowerCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "");

    if (forbiddenKeys.some(k => keyNorm.includes(k))) {
      continue;
    }

    out[key] = value;
  }

  return out;
}

function normalizePhoneFromSessionId(value) {
  const rawSession = cleanString(value);
  let digits = onlyDigits(rawSession);

  digits = digits.padEnd(18, "0").slice(0, 18);

  return `99${digits}`;
}

function normalizePhone(input) {
  const directPhone = firstFilled(
    input.phone,
    input.telefone,
    input.whatsapp,
    input.lead?.phone,
    input.contact?.phone,
    input.sender?.phone,
    input.body?.phone,
    input.body?.telefone,
    input.body?.whatsapp,
    input.body?.lead?.phone,
    input.metadata?.phone,
    input.metadata?.telefone,
    input.metadata?.whatsapp
  );

  const digits = onlyDigits(directPhone);

  if (digits.length >= 10) {
    return digits;
  }

  return normalizePhoneFromSessionId(
    firstFilled(
      input.sessionId,
      input.body?.sessionId,
      input.chat?.sessionId,
      input.metadata?.sessionId,
      "test-sem-session"
    )
  );
}

function normalizeSessionId(input, phone) {
  return firstFilled(
    input.sessionId,
    input.body?.sessionId,
    input.chat?.sessionId,
    input.metadata?.sessionId,
    input.chat_history_uuid,
    input.lead?.chat_history_uuid,
    `test-session-${phone}`
  );
}

function normalizeChatInput(input) {
  return firstFilled(
    input.chatInput,
    input.message?.content,
    input.message,
    input.text,
    input.body?.chatInput,
    input.body?.message,
    input.body?.text,
    input.content,
    ""
  );
}

function normalizeCaesJson(input) {
  const caes = normalizeArray(
    input.caes_json ||
    input.inputs?.caes_json ||
    input.body?.caes_json ||
    input.body?.inputs?.caes_json
  );

  return caes.filter(cao => isObject(cao));
}

function buildResumoLead({ phone, input, baseResumo }) {
  const resumo = isObject(baseResumo) ? baseResumo : {};

  return {
    tutor_nome: firstFilled(
      resumo.tutor_nome,
      input.tutor_nome,
      input.name,
      input.nome,
      input.sender?.name,
      input.contact?.name,
      ""
    ),

    tutor_telefone: firstFilled(
      resumo.tutor_telefone,
      phone
    ),

    email_tutor: firstFilled(
      resumo.email_tutor,
      input.email,
      input.email_tutor,
      ""
    ),

    unidade_preferida: firstFilled(
      resumo.unidade_preferida,
      "nao_definida"
    ),

    servico_interesse: firstFilled(
      resumo.servico_interesse,
      input.servico_interesse,
      input.service_interest,
      "nao_definido"
    ),

    periodo_desejado: firstFilled(
      resumo.periodo_desejado,
      input.periodo_desejado,
      ""
    ),

    data_desejada: firstFilled(
      resumo.data_desejada,
      input.data_desejada,
      ""
    ),

    data_checkin_desejada: firstFilled(
      resumo.data_checkin_desejada,
      input.data_checkin_desejada,
      ""
    ),

    data_checkout_desejada: firstFilled(
      resumo.data_checkout_desejada,
      input.data_checkout_desejada,
      ""
    ),

    origem_lead: firstFilled(
      resumo.origem_lead,
      input.origem_lead,
      "anuncio_whatsapp"
    ),

    origem_detalhada: firstFilled(
      resumo.origem_detalhada,
      input.origem_detalhada,
      "chat_n8n_teste"
    ),

    comprovante_recebido: toBool(
      resumo.comprovante_recebido,
      false
    ),

    tipo_comprovante: firstFilled(
      resumo.tipo_comprovante,
      "nao_informado"
    ),

    arquivo_comprovante_referencia: firstFilled(
      resumo.arquivo_comprovante_referencia,
      ""
    ),

    data_hora_avaliacao: "",
    data_hora_pre_reserva: "",
    pre_reserva_criada: false,

    responsavel_humano: firstFilled(
      resumo.responsavel_humano,
      ""
    ),

    observacoes: firstFilled(
      resumo.observacoes,
      ""
    )
  };
}

function buildChatHistoryUuid({ input, sessionId, phone }) {
  const existing = firstFilled(
    input.chat_history_uuid,
    input.lead?.chat_history_uuid,
    input.memory?.chat_history_uuid,
    input.body?.chat_history_uuid,
    input.body?.lead?.chat_history_uuid
  );

  if (existing) return existing.slice(0, 180);

  return `test:bruna:session:${sessionId}:phone:${phone}`.slice(0, 180);
}

const chatInput = normalizeChatInput(input);
const phone = normalizePhone(input);
const sessionId = normalizeSessionId(input, phone);
const chatHistoryUuid = buildChatHistoryUuid({ input, sessionId, phone });

if (!phone) {
  throw new Error("phone_teste_invalido: lead.phone não foi criado.");
}

if (!chatHistoryUuid) {
  throw new Error("chat_history_uuid_invalido: chat_history_uuid não foi criado.");
}

const caesJson = normalizeCaesJson(input);
const nowIso = new Date().toISOString();

const currentMessageId = safeNumber(
  firstFilled(
    input.message_id,
    input.messageId,
    input.message?.current_message_id,
    input.body?.message_id,
    input.body?.messageId
  ),
  Date.now()
);

const conversationId = safeNumber(
  firstFilled(
    input.conversation_id,
    input.chatwoot?.conversation_id,
    input.body?.conversation_id
  ),
  Number(String(phone).slice(-9))
);

const contactId = safeNumber(
  firstFilled(
    input.contact_id,
    input.chatwoot?.contact_id,
    input.body?.contact_id
  ),
  Number(String(phone).slice(-8))
);

const accountId = safeNumber(
  firstFilled(
    input.account_id,
    input.chatwoot?.account_id,
    input.body?.account_id
  ),
  990001
);

const inboxId = safeNumber(
  firstFilled(
    input.inbox_id,
    input.chatwoot?.inbox_id,
    input.body?.inbox_id
  ),
  990001
);

const baseResumoLead =
  input.inputs?.resumo_lead ||
  input.resumo_lead ||
  input.memory?.resumo_lead_json ||
  input.body?.inputs?.resumo_lead ||
  {};

const resumoLead = buildResumoLead({
  phone,
  input,
  baseResumo: baseResumoLead
});

const explicitIsFirstTurn =
  input.inputs?.is_first_turn ??
  input.is_first_turn ??
  input.body?.inputs?.is_first_turn ??
  input.body?.is_first_turn;

const hasExistingMemorySignal = Boolean(
  input.memory?.status_lead ||
  input.memory?.payload_ultima_resposta_json ||
  input.memory?.caes_json?.length ||
  input.inputs?.status_lead ||
  input.inputs?.ultima_intencao ||
  input.message?.history_for_crm
);

const isFirstTurn = explicitIsFirstTurn !== undefined
  ? toBool(explicitIsFirstTurn, true)
  : !hasExistingMemorySignal;

const messageContent = chatInput;

const labels = normalizeArray(
  input.labels ||
  input.chatwoot?.labels ||
  input.body?.labels
);

const normalizedLabels = labels.length
  ? labels
  : ["teste-bruna", "chat-n8n"];

const statusLead = firstFilled(
  input.inputs?.status_lead,
  input.memory?.status_lead,
  "NOVO_LEAD"
);

const ultimaIntencao = firstFilled(
  input.inputs?.ultima_intencao,
  input.memory?.ultima_intencao,
  ""
);

const eventoSistema = firstFilled(
  input.inputs?.evento_sistema,
  input.memory?.evento_sistema_atual,
  ""
);

const proximaAcao = firstFilled(
  input.inputs?.proxima_acao,
  input.memory?.proxima_acao,
  ""
);

const statusPagamento = firstFilled(
  input.inputs?.status_pagamento,
  input.memory?.status_pagamento,
  "nao_solicitado"
);

const aptoParaAvaliacao = firstFilled(
  input.inputs?.apto_para_avaliacao,
  input.memory?.apto_para_avaliacao,
  "pendente"
);

const debug = {
  normaliza_entrada_teste_version: "v3_corrige_is_first_turn_reference",
  phone_criado: Boolean(phone),
  chat_history_uuid_criado: Boolean(chatHistoryUuid),
  message_content_criado: Boolean(messageContent),
  is_first_turn: isFirstTurn,
  is_first_turn_explicit_input: explicitIsFirstTurn !== undefined,
  has_existing_memory_signal: hasExistingMemorySignal,
  quantidade_caes: caesJson.length,
  created_at: nowIso
};

return [
  {
    json: {
      run_mode: firstFilled(input.run_mode, "sandbox"),
      origem_execucao: firstFilled(input.origem_execucao, "chat_n8n_teste"),
      action: firstFilled(input.action, "sendMessage"),
      sessionId,
      chatInput: messageContent,

      lead: {
        phone,
        chat_history_uuid: chatHistoryUuid,
        sender_name: firstFilled(
          input.lead?.sender_name,
          input.sender?.name,
          input.contact?.name,
          input.name,
          input.nome,
          ""
        )
      },

      chatwoot: {
        account_id: accountId,
        inbox_id: inboxId,
        conversation_id: conversationId,
        contact_id: contactId,
        message_id: currentMessageId,
        labels: normalizedLabels,
        event: firstFilled(input.event, input.chatwoot?.event, "message_created"),
        system_event: firstFilled(input.system_event, input.chatwoot?.system_event, "MESSAGE_RECEIVED")
      },

      message: {
        content: messageContent,
        message_modality: "text_only",
        has_text: messageContent.length > 0,
        has_attachment: toBool(input.message?.has_attachment || input.has_attachment, false),
        data_url: firstFilled(input.message?.data_url, input.data_url, ""),
        current_message_id: currentMessageId,

        history_for_crm: firstFilled(
          input.message?.history_for_crm,
          input.history_for_crm,
          ""
        ),

        last_bruna_message_before_current_block: firstFilled(
          input.message?.last_bruna_message_before_current_block,
          input.last_bruna_message_before_current_block,
          ""
        ),

        last_bruna_question_before_current_block: firstFilled(
          input.message?.last_bruna_question_before_current_block,
          input.last_bruna_question_before_current_block,
          ""
        ),

        last_human_message_before_current_block: firstFilled(
          input.message?.last_human_message_before_current_block,
          input.last_human_message_before_current_block,
          ""
        )
      },

      inputs: {
        is_first_turn: isFirstTurn,

        status_lead: statusLead,
        ultima_intencao: ultimaIntencao,
        evento_sistema: eventoSistema,
        proxima_acao: proximaAcao,

        status_pagamento: statusPagamento,
        apto_para_avaliacao: aptoParaAvaliacao,

        caes_json: caesJson,
        quantidade_caes: caesJson.length,

        precisa_responder_preco: toBool(input.inputs?.precisa_responder_preco, false),
        precisa_responder_localizacao: toBool(input.inputs?.precisa_responder_localizacao, false),
        precisa_responder_visita_material: toBool(input.inputs?.precisa_responder_visita_material, false),
        deve_priorizar_base_conhecimento: toBool(input.inputs?.deve_priorizar_base_conhecimento, false),

        turn_signals: isObject(input.inputs?.turn_signals)
          ? input.inputs.turn_signals
          : {},

        resumo_lead: resumoLead
      },

      memory: {
        phone,
        chat_history_uuid: chatHistoryUuid,

        nome_tutor: firstFilled(
          input.memory?.nome_tutor,
          resumoLead.tutor_nome,
          ""
        ),

        email_tutor: firstFilled(
          input.memory?.email_tutor,
          resumoLead.email_tutor,
          ""
        ),

        quantidade_caes: caesJson.length,
        caes_json: caesJson,

        unidade_preferida: resumoLead.unidade_preferida,
        servico_interesse: resumoLead.servico_interesse,
        origem_lead: resumoLead.origem_lead,
        origem_detalhada: resumoLead.origem_detalhada,

        status_lead: statusLead,
        ultima_intencao: ultimaIntencao,
        evento_sistema_atual: eventoSistema,

        status_pagamento: statusPagamento,
        apto_para_avaliacao: aptoParaAvaliacao,
        proxima_acao: proximaAcao,

        resumo_lead_json: resumoLead,

        payload_ultima_resposta_json: isObject(input.memory?.payload_ultima_resposta_json)
          ? input.memory.payload_ultima_resposta_json
          : {}
      },

      config_bruna_modelo: removeSensitivePixLikeData(
        isObject(input.config_bruna_modelo)
          ? input.config_bruna_modelo
          : {}
      ),

      config_bruna_modelo_resumido: removeSensitivePixLikeData(
        isObject(input.config_bruna_modelo_resumido)
          ? input.config_bruna_modelo_resumido
          : {}
      ),

      debug_contexto: {
        normaliza_entrada_teste: debug
      },

      criado_em_teste: nowIso
    }
  }
];

function parseMaybeJson(value, fallback) {
  if (value === undefined || value === null || value === "") return fallback;
  if (typeof value === "object") return value;

  try {
    return JSON.parse(value);
  } catch (e) {
    const text = String(value || "").trim();
    const match = text.match(/\{[\s\S]*\}/);

    if (match) {
      try {
        return JSON.parse(match[0]);
      } catch (e2) {}
    }

    return fallback;
  }
}

function clone(value) {
  return JSON.parse(JSON.stringify(value || {}));
}

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function normalizeEnum(value, allowed, fallback) {
  const v = String(value || "").trim();
  return allowed.includes(v) ? v : fallback;
}

function toBool(value) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1) return true;
  if (value === 0) return false;

  const text = String(value || "")
    .trim()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");

  if (["1", "true", "sim", "yes", "t"].includes(text)) return true;
  if (["0", "false", "nao", "não", "no", "f"].includes(text)) return false;

  return false;
}

function toNumber(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function cleanText(value) {
  return String(value || "").trim();
}

function cleanArray(value) {
  if (!Array.isArray(value)) return [];
  return value;
}

function compactCandidatas(value) {
  const arr = cleanArray(value);

  return arr
    .filter(item => isObject(item))
    .map(item => ({
      raca_canonica: cleanText(item.raca_canonica),
      score: toNumber(item.score),
      potencial_dano: toBool(item.potencial_dano),
      aceita_auauzin: toBool(item.aceita_auauzin),
      aceita_auauzin_origem: cleanText(item.aceita_auauzin_origem),
      tipo_registro_match: cleanText(item.tipo_registro_match),
      nome_digitado_match: cleanText(item.nome_digitado_match)
    }))
    .filter(item => item.raca_canonica)
    .slice(0, 5);
}

function compactRegrasRaca(value) {
  const regra = isObject(value) ? value : {};

  if (!Object.keys(regra).length) return {};

  let statusRaca = normalizeEnum(
    regra.status_raca,
    [
      "sem_raca_informada",
      "precisa_confirmar_raca",
      "bloqueado_potencial_dano",
      "raca_ok"
    ],
    "sem_raca_informada"
  );

  let decisaoConclusiva = toBool(regra.decisao_raca_conclusiva);
  let precisaConfirmacao = toBool(regra.precisa_confirmacao_antes_decisao);

  if (statusRaca === "raca_ok" && decisaoConclusiva !== true) {
    statusRaca = "precisa_confirmar_raca";
    precisaConfirmacao = true;
  }

  if (statusRaca === "precisa_confirmar_raca") {
    decisaoConclusiva = false;
    precisaConfirmacao = true;
  }

  if (statusRaca === "sem_raca_informada") {
    decisaoConclusiva = false;
    precisaConfirmacao = true;
  }

  return {
    raca_original: cleanText(regra.raca_original),
    raca_canonica: cleanText(regra.raca_canonica),
    raca_canonica_norm: cleanText(regra.raca_canonica_norm),

    porte_classificado: normalizeEnum(
      regra.porte_classificado,
      ["mini", "pequeno", "medio", "grande", "gigante", "nao_definido"],
      "nao_definido"
    ),

    aceita_auauzin: toBool(regra.aceita_auauzin),
    aceita_auauzin_origem: cleanText(regra.aceita_auauzin_origem),

    potencial_dano: toBool(regra.potencial_dano),

    raca_encontrada: toBool(regra.raca_encontrada),
    deve_confirmar_raca: toBool(regra.deve_confirmar_raca),

    status_raca: statusRaca,

    decisao_raca_conclusiva: decisaoConclusiva,
    precisa_confirmacao_antes_decisao: precisaConfirmacao,

    pode_seguir_amaralina_por_raca: toBool(regra.pode_seguir_amaralina_por_raca),
    pode_seguir_auauzin_por_raca: toBool(regra.pode_seguir_auauzin_por_raca),

    motivo_raca: cleanText(regra.motivo_raca),
    escopo_decisao: "por_cao",

    score_match: toNumber(regra.score_match),
    tipo_match: cleanText(regra.tipo_match),
    tipo_registro_match: cleanText(regra.tipo_registro_match),
    nome_digitado_match: cleanText(regra.nome_digitado_match),

    qtd_racas_candidatas: toNumber(regra.qtd_racas_candidatas),
    qtd_matches_mesma_canonica: toNumber(regra.qtd_matches_mesma_canonica),
    qtd_grafias_mesma_canonica: toNumber(regra.qtd_grafias_mesma_canonica),
    total_grafias_canonica: toNumber(regra.total_grafias_canonica),
    possui_linha_canonica: toBool(regra.possui_linha_canonica),

    score_top_1: toNumber(regra.score_top_1),
    score_top_2: toNumber(regra.score_top_2),
    gap_score: toNumber(regra.gap_score),

    nivel_confianca_raca: normalizeEnum(
      regra.nivel_confianca_raca,
      ["sem_raca", "baixa", "media", "alta"],
      ""
    ),

    racas_candidatas: compactCandidatas(regra.racas_candidatas)
  };
}

function normalizeDog(dog = {}) {
  const regra = compactRegrasRaca(dog.regras_raca);

  const statusRaca = regra.status_raca || "";
  const decisaoConclusiva = regra.decisao_raca_conclusiva === true;

  const shouldApplyCanonicalBreed =
    regra.raca_encontrada === true &&
    decisaoConclusiva === true &&
    statusRaca !== "precisa_confirmar_raca" &&
    statusRaca !== "sem_raca_informada";

  const shouldApplyBreedPorte =
    shouldApplyCanonicalBreed &&
    regra.porte_classificado &&
    regra.porte_classificado !== "nao_definido";

  const basePorte = normalizeEnum(
    dog.porte,
    ["mini", "pequeno", "medio", "grande", "gigante", "nao_definido"],
    "nao_definido"
  );

  const sexo = normalizeEnum(
    dog.sexo,
    ["macho", "femea", "nao_informado"],
    "nao_informado"
  );

  return {
    nome: cleanText(dog.nome),
    idade_anos: cleanText(dog.idade_anos),
    idade_texto: cleanText(dog.idade_texto),
    raca: cleanText(dog.raca),

    raca_canonica: shouldApplyCanonicalBreed
      ? cleanText(regra.raca_canonica)
      : cleanText(dog.raca_canonica),

    porte: shouldApplyBreedPorte
      ? regra.porte_classificado
      : basePorte,

    sexo,

    castrado: normalizeEnum(
      dog.castrado,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    no_cio: sexo === "macho"
      ? "nao_se_aplica"
      : normalizeEnum(
          dog.no_cio,
          ["sim", "nao", "nao_se_aplica", "nao_informado"],
          "nao_informado"
        ),

    vacinas_ok: normalizeEnum(
      dog.vacinas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    antipulgas_ok: normalizeEnum(
      dog.antipulgas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    vermifugacao_ok: normalizeEnum(
      dog.vermifugacao_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    perfil_comportamental: normalizeEnum(
      dog.perfil_comportamental,
      [
        "nao_informado",
        "tranquilo",
        "sociavel",
        "seletivo",
        "reativo_leve",
        "reativo_alto",
        "agressivo",
        "indeterminado"
      ],
      "nao_informado"
    ),

    comportamento_observacoes: cleanText(dog.comportamento_observacoes),

    possui_relatorio_veterinario: normalizeEnum(
      dog.possui_relatorio_veterinario,
      ["sim", "nao", "nao_se_aplica", "nao_informado"],
      "nao_informado"
    ),

