    ["sim", "nao", "caso_cinzento", "pendente"],
    "pendente",
    "apto_para_avaliacao"
  );
}

const previousStatusPagamento = enumValue(
  inputs.status_pagamento || memory.status_pagamento || "nao_solicitado",
  [
    "nao_solicitado",
    "aguardando_pagamento",
    "comprovante_recebido",
    "validacao_humana_pendente",
    "aprovado_humano",
    "negado_humano",
    "estornado",
    "cancelado"
  ],
  "nao_solicitado",
  "status_pagamento"
);

let statusPagamento = "nao_solicitado";

if (resumo.comprovante_recebido === true) {
  statusPagamento = "validacao_humana_pendente";
} else if (deveSolicitarPagamento === true) {
  statusPagamento = "aguardando_pagamento";
} else if (
  previousStatusPagamento &&
  previousStatusPagamento !== "aguardando_pagamento" &&
  previousStatusPagamento !== "comprovante_recebido"
) {
  statusPagamento = previousStatusPagamento;
} else {
  statusPagamento = "nao_solicitado";
}

const guiaEnviado =
  toBool(inputs.guia_enviado) ||
  toBool(memory.guia_enviado) ||
  eventoSistema === "GUIA_ENVIADO";

const runMode = enumValue(
  ctx.run_mode || "sandbox",
  ["prod", "sandbox", "shadow"],
  "sandbox",
  "run_mode"
);

const promptVersion = cleanString(
  ctx.prompt_version ||
