const contactId = safeNumber(chatwoot.contact_id);
const conversationId = safeNumber(chatwoot.conversation_id);

const phone = cleanString(lead.phone || memory.phone || resumo.tutor_telefone);
const chatHistoryUuid = cleanString(lead.chat_history_uuid || memory.chat_history_uuid);

if (!phone) {
  throw new Error("phone_obrigatorio_para_persistencia");
}

const rawMessageId = cleanString(
  message.current_message_id ||
  chatwoot.message_id
);

const messageId = rawMessageId || `sem_id_${phone}_${Date.now()}`;

const lastProcessedMessageId = rawMessageId || String(Date.now());

const dataCheckinSql = sqlDateOrNull(
