);

const dataCheckoutSql = sqlDateOrNull(
  resumo.data_checkout_desejada,
  "resumo_lead.data_checkout_desejada"
);

const dataDesejadaSql = sqlDateOrNull(
  resumo.data_desejada,
  "resumo_lead.data_desejada"
);

const outputBruna = {
  status_lead: statusLead,
  ultima_intencao: ultimaIntencao,
  evento_sistema: eventoSistema,
  mensagens_resposta: shouldReply ? mensagensResposta : [],
