};

const motivoPreReprovacao = cleanString(inputs.motivo_pre_reprovacao);

const etapaDebug = ctx.origem_execucao || "bruna_fluxo";
const nodeNameDebug = ctx.node_name || "Monta SQL Persistência";

const qaTagsLead = [
  etapaDebug,
  "inputs_caes_unico",
  MONTA_SQL_PERSISTENCIA_VERSION,
  ...(turnSignals.pediu_preco === true ? ["pediu_preco"] : []),
  ...(turnSignals.insistiu_preco === true ? ["insistiu_preco"] : []),
  ...(turnSignals.lead_pretende_castrar === true ? ["lead_pretende_castrar"] : []),
  ...(turnSignals.lead_nao_pretende_castrar === true ? ["lead_nao_pretende_castrar"] : []),
  ...(turnSignals.lead_finalizou_atendimento === true ? ["lead_finalizou_atendimento"] : [])
];

const qaTagsBruna = [
  etapaDebug,
  "inputs_caes_unico",
  MONTA_SQL_PERSISTENCIA_VERSION,
  ...(Object.keys(brunaOverride || {}).length > 0 ? ["bruna_override"] : []),
  ...(Object.keys(brunaSystemGuard || {}).length > 0 ? ["bruna_system_guard"] : []),
  ...(turnSignals.insistiu_preco === true ? ["insistiu_preco"] : []),
  ...(turnSignals.lead_pretende_castrar === true ? ["lead_pretende_castrar"] : []),
