const raw = $input.first().json || {};
const NORMALIZA_BRUNA_VERSION = "v16_guard_atual_sem_override_antigo";

function getNodeJson(nodeName) {
  try {
    return $(nodeName).first().json || {};
  } catch (e) {
    return {};
  }
}

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function isNonEmptyObject(value) {
  return isObject(value) && Object.keys(value).length > 0;
}

function firstObject(...values) {
  for (const value of values) {
    if (isNonEmptyObject(value)) return value;
  }
  return {};
}

function clean(value) {
  if (value === undefined || value === null) return "";

  if (typeof value === "object") {
    try {
      return JSON.stringify(value);
    } catch (e) {
      return "";
    }
  }

  return String(value).trim();
}

function norm(value) {
  return clean(value)
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function toBool(value) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1) return true;
  if (value === 0) return false;

  const t = norm(value);

  if (["1", "true", "sim", "yes", "s"].includes(t)) return true;
  if (["0", "false", "nao", "não", "no", "n"].includes(t)) return false;

  return false;
}

function parseJsonFlexible(value) {
  if (value === undefined || value === null) return {};

  if (typeof value === "object") return value;

  let text = String(value || "").trim();

  text = text
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();

  const firstBrace = text.indexOf("{");
  const lastBrace = text.lastIndexOf("}");

  if (firstBrace >= 0 && lastBrace > firstBrace) {
    text = text.slice(firstBrace, lastBrace + 1);
  }

  try {
    return JSON.parse(text);
  } catch (error) {
    return {
      __parse_error: true,
      __parse_error_message: error.message,
      __raw_text: value
    };
  }
}

function unwrapBrunaOutput(value) {
  const parsed = parseJsonFlexible(value);

  if (!isObject(parsed)) {
    return {
      bruna: {},
      parse_error: true,
      raw_parsed: parsed
    };
  }

  if (parsed.__parse_error === true) {
    return {
      bruna: parsed,
      parse_error: true,
      raw_parsed: parsed
    };
  }

  if (typeof parsed.output === "string") {
    const nested = parseJsonFlexible(parsed.output);

    if (nested.__parse_error === true) {
      return {
        bruna: nested,
        parse_error: true,
        raw_parsed: parsed
      };
    }

    if (isObject(nested)) {
      const merged = {
        ...parsed,
        ...nested
      };

      delete merged.output;

      return {
        bruna: merged,
        parse_error: false,
        raw_parsed: parsed
      };
    }
  }

  if (isObject(parsed.output)) {
    const merged = {
      ...parsed,
      ...parsed.output
    };

    delete merged.output;

    return {
      bruna: merged,
      parse_error: false,
      raw_parsed: parsed
    };
  }

  for (const key of ["text", "response", "chatOutput"]) {
    if (typeof parsed[key] === "string") {
      const nested = parseJsonFlexible(parsed[key]);

      if (!nested.__parse_error && isObject(nested)) {
        const merged = {
          ...parsed,
          ...nested
        };

        delete merged[key];

        return {
          bruna: merged,
          parse_error: false,
          raw_parsed: parsed
        };
      }
    }
  }

  return {
    bruna: parsed,
    parse_error: false,
    raw_parsed: parsed
  };
}

function parseArray(value) {
  if (Array.isArray(value)) return value;

  if (typeof value === "string" && value.trim()) {
    try {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      return [];
    }
  }

  return [];
}

function enumValue(value, allowed, fallback, warnings, path = "") {
  const v = clean(value);

  if (allowed.includes(v)) return v;

  if (v && path) {
    warnings.push({
      path,
      raw: v,
      result: fallback,
      reason: "enum_invalido_usado_fallback"
    });
  }

  return fallback;
}

function firstFilled(...values) {
  for (const value of values) {
    const v = clean(value);
    if (v !== "") return v;
  }

  return "";
}

function normalizeMessages(value) {
  const arr = Array.isArray(value) ? value : [];

  return arr
    .map(clean)
    .filter(Boolean)
    .slice(0, 4);
}

function hasValue(value) {
  const t = norm(value);

  return Boolean(
    t &&
    ![
      "nao informado",
      "nao_informado",
      "não informado",
      "nao definido",
      "nao_definido",
      "não definido",
      "nao se aplica",
      "nao_se_aplica",
      "não se aplica"
    ].includes(t)
  );
}

function normalizeDog(dog = {}) {
  const out = {
    nome: clean(dog.nome),
    idade_anos: clean(dog.idade_anos),
    idade_texto: clean(dog.idade_texto),
    raca: clean(dog.raca),
    raca_canonica: clean(dog.raca_canonica),

    porte: ["mini", "pequeno", "medio", "grande", "gigante", "nao_definido"].includes(clean(dog.porte))
      ? clean(dog.porte)
      : "nao_definido",

    sexo: ["macho", "femea", "nao_informado"].includes(clean(dog.sexo))
      ? clean(dog.sexo)
      : "nao_informado",

    castrado: ["sim", "nao", "nao_informado"].includes(clean(dog.castrado))
      ? clean(dog.castrado)
      : "nao_informado",

    no_cio: ["sim", "nao", "nao_se_aplica", "nao_informado"].includes(clean(dog.no_cio))
      ? clean(dog.no_cio)
      : "nao_informado",

    vacinas_ok: ["sim", "nao", "nao_informado"].includes(clean(dog.vacinas_ok))
      ? clean(dog.vacinas_ok)
      : "nao_informado",

    antipulgas_ok: ["sim", "nao", "nao_informado"].includes(clean(dog.antipulgas_ok))
      ? clean(dog.antipulgas_ok)
      : "nao_informado",

    vermifugacao_ok: ["sim", "nao", "nao_informado"].includes(clean(dog.vermifugacao_ok))
      ? clean(dog.vermifugacao_ok)
      : "nao_informado",

    perfil_comportamental: [
      "nao_informado",
      "sociavel",
      "seletivo",
      "reativo_leve",
      "reativo_alto",
      "agressivo",
      "indeterminado",
      "tranquilo"
    ].includes(clean(dog.perfil_comportamental))
      ? clean(dog.perfil_comportamental)
      : "nao_informado",

    comportamento_observacoes: clean(dog.comportamento_observacoes),

    possui_relatorio_veterinario: [
      "sim",
      "nao",
      "nao_se_aplica",
      "nao_informado"
    ].includes(clean(dog.possui_relatorio_veterinario))
      ? clean(dog.possui_relatorio_veterinario)
      : "nao_informado",

    observacoes: clean(dog.observacoes),
    regras_raca: isObject(dog.regras_raca) ? dog.regras_raca : {}
  };

  if (out.sexo === "macho") {
    out.no_cio = "nao_se_aplica";
  }

  return out;
}

function isRealDog(dog = {}) {
  const d = normalizeDog(dog);

  return (
    hasValue(d.nome) ||
    hasValue(d.idade_anos) ||
    hasValue(d.idade_texto) ||
    hasValue(d.raca) ||
    hasValue(d.raca_canonica) ||
    ["macho", "femea"].includes(d.sexo)
  );
}

function ageMonths(dog = {}) {
  const idadeTexto = norm(dog.idade_texto);
  const idadeAnos = clean(dog.idade_anos);

  const mesesMatch = idadeTexto.match(/(\d{1,2})\s*(mes|meses)/);
  if (mesesMatch) return Number(mesesMatch[1]);

  const anosMatch = idadeTexto.match(/(\d{1,2})\s*(ano|anos)/);
  if (anosMatch) return Number(anosMatch[1]) * 12;

  if (/^\d+$/.test(idadeAnos)) return Number(idadeAnos) * 12;

  return null;
}

function isMaleAdult(dog = {}) {
  const months = ageMonths(dog);
  return dog.sexo === "macho" && months !== null && months >= 8;
}

function basicComplete(dog = {}) {
  return (
    hasValue(dog.nome) &&
    (hasValue(dog.idade_anos) || hasValue(dog.idade_texto)) &&
    hasValue(dog.raca) &&
    ["macho", "femea"].includes(dog.sexo)
  );
}

function sanitaryComplete(dog = {}) {
  return (
    dog.vacinas_ok === "sim" &&
    dog.antipulgas_ok === "sim" &&
    dog.vermifugacao_ok === "sim"
  );
}

function behaviorComplete(dog = {}) {
  return (
    dog.perfil_comportamental !== "nao_informado" ||
    hasValue(dog.comportamento_observacoes)
  );
}

function raceStatus(dog = {}) {
  return clean(dog.regras_raca?.status_raca || "sem_raca_informada");
}

function raceConclusive(dog = {}) {
  return dog.regras_raca?.decisao_raca_conclusiva === true;
}

function dogName(dog = {}, index = 0) {
  const nome = clean(dog.nome);
  return nome || `cão ${index + 1}`;
}

function stripDogCopies(obj = {}) {
  const out = { ...(isObject(obj) ? obj : {}) };

  delete out.caes_json;
  delete out.quantidade_caes;
  delete out.regras_raca;

  delete out.caes;
  delete out.cao_nome;
  delete out.cao_idade_anos;
  delete out.cao_idade_texto;
  delete out.cao_raca;
  delete out.cao_porte;
  delete out.cao_sexo;
  delete out.cao_castrado;
  delete out.cao_no_cio;
  delete out.cao_vacinas_ok;
  delete out.cao_antipulgas_ok;
  delete out.cao_vermifugacao_ok;
  delete out.cao_perfil_comportamental;
  delete out.cao_comportamento_observacoes;
  delete out.possui_relatorio_veterinario;

  return out;
}

function normalizeResumoLead(base = {}, incoming = {}, context = {}, deveRepassarHumano = false) {
  const previous = stripDogCopies(base);
  const next = stripDogCopies(incoming);

  const comprovanteRecebido = toBool(next.comprovante_recebido ?? previous.comprovante_recebido);

  return {
    tutor_nome: firstFilled(next.tutor_nome, previous.tutor_nome, context.lead?.sender_name),
    tutor_telefone: firstFilled(next.tutor_telefone, previous.tutor_telefone, context.lead?.phone),
    email_tutor: firstFilled(next.email_tutor, previous.email_tutor),

    unidade_preferida: ["amaralina", "auauzin_patamares", "nao_definida"].includes(firstFilled(next.unidade_preferida, previous.unidade_preferida))
      ? firstFilled(next.unidade_preferida, previous.unidade_preferida)
      : "nao_definida",

    servico_interesse: ["creche", "hotel", "creche_e_hotel", "visita", "nao_definido"].includes(firstFilled(next.servico_interesse, previous.servico_interesse))
      ? firstFilled(next.servico_interesse, previous.servico_interesse)
      : "nao_definido",

    periodo_desejado: firstFilled(next.periodo_desejado, previous.periodo_desejado),
    data_desejada: firstFilled(next.data_desejada, previous.data_desejada),
    data_checkin_desejada: firstFilled(next.data_checkin_desejada, previous.data_checkin_desejada),
    data_checkout_desejada: firstFilled(next.data_checkout_desejada, previous.data_checkout_desejada),

    origem_lead: firstFilled(
      next.origem_lead,
      previous.origem_lead,
      context.lead?.origem_lead,
      "outro"
    ),

    origem_detalhada: firstFilled(
      next.origem_detalhada,
      previous.origem_detalhada,
      context.lead?.entry_channel,
      context.lead?.origem_detalhada
    ),

    comprovante_recebido: comprovanteRecebido,
    tipo_comprovante: comprovanteRecebido
      ? (
          ["imagem", "pdf", "print_banco", "nao_informado"].includes(firstFilled(next.tipo_comprovante, previous.tipo_comprovante))
            ? firstFilled(next.tipo_comprovante, previous.tipo_comprovante)
            : "nao_informado"
        )
      : "nao_informado",

    arquivo_comprovante_referencia: firstFilled(
      next.arquivo_comprovante_referencia,
      previous.arquivo_comprovante_referencia
    ),

    data_hora_avaliacao: "",
    data_hora_pre_reserva: "",
    pre_reserva_criada: false,

    responsavel_humano: deveRepassarHumano ? "Flavia" : "",

    observacoes: firstFilled(next.observacoes, previous.observacoes)
  };
}

function normalizeResumoRepasse(base = {}, incoming = {}, resumoLead = {}, deveRepassarHumano = false, motivoRepasse = "") {
  const previous = stripDogCopies(base);
  const next = stripDogCopies(incoming);

  return {
    repassar_para: deveRepassarHumano ? "Flavia" : "",
    motivo: deveRepassarHumano ? firstFilled(motivoRepasse, next.motivo, previous.motivo, "repasse_humano") : "",

    tutor_nome: firstFilled(next.tutor_nome, previous.tutor_nome, resumoLead.tutor_nome),
    tutor_telefone: firstFilled(next.tutor_telefone, previous.tutor_telefone, resumoLead.tutor_telefone),

    unidade_preferida: ["amaralina", "auauzin_patamares", "nao_definida"].includes(firstFilled(next.unidade_preferida, previous.unidade_preferida, resumoLead.unidade_preferida))
      ? firstFilled(next.unidade_preferida, previous.unidade_preferida, resumoLead.unidade_preferida)
      : "nao_definida",

    servico_interesse: ["creche", "hotel", "creche_e_hotel", "visita", "nao_definido"].includes(firstFilled(next.servico_interesse, previous.servico_interesse, resumoLead.servico_interesse))
      ? firstFilled(next.servico_interesse, previous.servico_interesse, resumoLead.servico_interesse)
      : "nao_definido",

    data_hora_avaliacao: "",
    comprovante_recebido: resumoLead.comprovante_recebido === true,
    tipo_comprovante: resumoLead.tipo_comprovante || "nao_informado",

    observacoes: firstFilled(next.observacoes, previous.observacoes, resumoLead.observacoes)
  };
}

function labelIndicaHumanoAssumiu(labels = []) {
  return labels.some(label => {
    const l = norm(label);

    return (
      l === "humano assumiu" ||
      l.includes("humano assumiu") ||
      l.includes("em atendimento humano") ||
      l.includes("atendimento humano")
    );
  });
}

function messageLooksLikePaymentRequest(messages = []) {
  const text = norm(messages.join(" "));

  return (
    text.includes("pix") ||
    text.includes("pagamento") ||
    text.includes("comprovante") ||
    text.includes("chave") ||
    text.includes("chave pix") ||
    text.includes("enviar pix") ||
    text.includes("fazer pix") ||
    text.includes("pagar agora") ||
    text.includes("pagamento agora")
  );
}

function messageLooksLikeWrongCastrationIntent(messages = []) {
  const text = norm(messages.join(" "));

  return (
    text.includes("pretende castrar") ||
    text.includes("pensa em castrar") ||
    text.includes("quer castrar") ||
    text.includes("vai castrar")
  );
}

function messageLooksLikeBreedBlock(messages = []) {
  const text = norm(messages.join(" "));

  return (
    text.includes("potencial de dano") ||
    text.includes("raca restrita") ||
    text.includes("raça restrita") ||
    text.includes("nao aceitamos") ||
    text.includes("não aceitamos")
  );
}

function messageLooksLikePriceAnswer(messages = []) {
  const raw = messages.join(" ");
  const text = norm(raw);

  return (
    /r\s*\$/.test(raw) ||
    text.includes("reais") ||
    text.includes("plano mensal") ||
    text.includes("diaria avulsa") ||
    text.includes("diária avulsa") ||
    text.includes("baixa temporada") ||
    text.includes("alta temporada")
  );
}

function cleanMemory(memory = {}) {
  const out = { ...(isObject(memory) ? memory : {}) };

  delete out.caes_json;
  delete out.quantidade_caes;
  delete out.resumo_lead_json;
  delete out.resumo_interno_repasse_json;
  delete out.payload_ultima_resposta_json;

  return out;
}

function hasPendingRace(dogs = []) {
  return dogs.some(dog => {
    const status = raceStatus(dog);

    return (
      status === "sem_raca_informada" ||
      status === "precisa_confirmar_raca" ||
      dog.regras_raca?.precisa_confirmacao_antes_decisao === true
    );
  });
}

function getPendingRaceDog(dogs = []) {
  return dogs.find(dog => {
    const status = raceStatus(dog);

    return (
      status === "sem_raca_informada" ||
      status === "precisa_confirmar_raca" ||
      dog.regras_raca?.precisa_confirmacao_antes_decisao === true
    );
  });
}

function allDogsBlockedByRace(dogs = []) {
  if (!dogs.length) return false;
  return dogs.every(dog => raceStatus(dog) === "bloqueado_potencial_dano");
}

function hasAllMinimumData(dogs = []) {
  if (!dogs.length) return false;

  return dogs.every(dog => {
    if (!basicComplete(dog)) return false;
    if (!sanitaryComplete(dog)) return false;
    if (!behaviorComplete(dog)) return false;

    if (dog.sexo === "femea" && dog.no_cio === "nao_informado") return false;
    if (dog.sexo === "femea" && dog.no_cio === "sim") return false;

    if (raceStatus(dog) !== "raca_ok") return false;
    if (!raceConclusive(dog)) return false;

    if (isMaleAdult(dog) && dog.castrado !== "sim") return false;

    return true;
  });
}

const warnings = [];

const start = firstObject(
  getNodeJson("Start"),
  getNodeJson("Normaliza Entrada"),
  getNodeJson("Normaliza Entrada Teste"),
  getNodeJson("When chat message received")
);

const contexto = firstObject(
  getNodeJson("Guard Rail Sistêmico Bruna"),
  getNodeJson("Aplica Regras de Raça"),
  getNodeJson("Normaliza Extrator e Prepara Raças"),
  getNodeJson("Monta Contexto Bruna Solo"),
  getNodeJson("CONTEXTO BRUNA"),
  getNodeJson("Monta Contexto Bruna")
);

const current = firstObject(raw, $input.first()?.json || {});

const base = {
  ...start,
  ...contexto,
  ...current,

  inputs: firstObject(current.inputs, contexto.inputs, start.inputs),
  message: firstObject(current.message, contexto.message, start.message),
  chatwoot: firstObject(current.chatwoot, contexto.chatwoot, start.chatwoot),
  lead: firstObject(current.lead, contexto.lead, start.lead),
  memory: firstObject(current.memory, contexto.memory, start.memory),

  config_bruna: firstObject(
    current.config_bruna,
    current.config_bruna_modelo,
    contexto.config_bruna,
    contexto.config_bruna_modelo,
    start.config_bruna,
    start.config_bruna_modelo
  )
};

const rawOutput =
  raw.output ??
  raw.text ??
  raw.response ??
  raw.chatOutput ??
  current.output ??
  current.text ??
  current.response ??
  current.chatOutput ??
  raw;

const unwrapped = unwrapBrunaOutput(rawOutput);
const bruna = isObject(unwrapped.bruna) ? unwrapped.bruna : {};

const previousInputs = isObject(base.inputs) ? base.inputs : {};
const previousResumo = isObject(previousInputs.resumo_lead) ? previousInputs.resumo_lead : {};
const previousRepasse = isObject(previousInputs.resumo_interno_repasse) ? previousInputs.resumo_interno_repasse : {};

const brunaSystemGuard = firstObject(
  current.bruna_system_guard,
  contexto.bruna_system_guard
);

const guardAplicouOverride = brunaSystemGuard?.aplicou_override === true;

const brunaOverrideRaw = guardAplicouOverride
  ? firstObject(
      current.bruna_override,
      contexto.bruna_override
    )
  : {};

const hasBrunaOverride =
  guardAplicouOverride &&
  isNonEmptyObject(brunaOverrideRaw);

const dogs = parseArray(previousInputs.caes_json)
  .map(normalizeDog)
  .filter(isRealDog);

let shouldReply = base.should_reply !== false;
let motivoBloqueioEnvio = base.should_reply === false
  ? firstFilled(base.motivo_bloqueio_envio, "should_reply_false_entrada")
  : "";

const labels = Array.isArray(base.chatwoot?.labels) ? base.chatwoot.labels : [];
const humanoAssumiu =
  labelIndicaHumanoAssumiu(labels) ||
  previousInputs.proxima_acao === "nao_responder_humano_assumiu";

let deveRepassarHumano = toBool(bruna.deve_repassar_humano);
let motivoRepasse = deveRepassarHumano
  ? firstFilled(bruna.motivo_repasse, bruna.resumo_interno_repasse?.motivo, "repasse_humano")
  : "";

let statusLead = enumValue(
  bruna.status_lead || previousInputs.status_lead,
  [
    "NOVO_LEAD",
    "COLETANDO_DADOS",
    "QUALIFICANDO",
    "PRE_REPROVADO",
    "APTO_PARA_AVALIACAO",
    "AGUARDANDO_PAGAMENTO",
    "COMPROVANTE_RECEBIDO",
    "TRANSFERIDO_FLAVIA",
    "ENCERRADO_NAO_PERFIL",
    "ENCERRADO_SEM_RESPOSTA",
    "ENCERRADO"
  ],
  previousInputs.status_lead || "QUALIFICANDO",
  warnings,
  "status_lead"
);

let ultimaIntencao = enumValue(
  bruna.ultima_intencao || previousInputs.ultima_intencao,
  [
    "INTERESSE_CRECHE",
    "INTERESSE_HOTEL",
    "PEDIU_VALOR",
    "PEDIU_LOCALIZACAO",
    "PEDIU_VISITA",
    "INFORMOU_DADOS_CAO",
    "INFORMOU_DADOS_TUTOR",
    "ACEITOU_AVALIACAO",
    "RECEBEU_PIX",
    "ENVIOU_COMPROVANTE",
    "PEDIU_HUMANO",
    "MACHO_NAO_CASTRADO",
    "RACA_POTENCIAL_DANO",
    "URGENCIA_FERIADO",
    "OBJECAO_PRECO",
    "SUMIU"
  ],
  previousInputs.ultima_intencao || "INFORMOU_DADOS_CAO",
  warnings,
  "ultima_intencao"
);

let eventoSistema = enumValue(
  bruna.evento_sistema,
  [
    "",
    "FORMULARIO_RECEBIDO",
    "GUIA_ENVIADO",
    "PIX_SOLICITADO",
    "ANEXO_RECEBIDO",
    "COMPROVANTE_IDENTIFICADO",
    "REPASSE_FLAVIA",
    "FOLLOWUP_DISPARADO",
    "CONVERSA_ENCERRADA"
  ],
  "",
  warnings,
  "evento_sistema"
);

let mensagensResposta = normalizeMessages(bruna.mensagens_resposta);
let proximaAcao = firstFilled(bruna.proxima_acao, previousInputs.proxima_acao, "aguardar_resposta_do_lead");

let deveEnviarGuia = toBool(bruna.deve_enviar_guia);
let deveSolicitarPagamento = toBool(bruna.deve_solicitar_pagamento);
let deveEncerrarConversa = toBool(bruna.deve_encerrar_conversa);

let resumoLead = normalizeResumoLead(previousResumo, bruna.resumo_lead, base, deveRepassarHumano);
let resumoInternoRepasse = normalizeResumoRepasse(
  previousRepasse,
  bruna.resumo_interno_repasse,
  resumoLead,
  deveRepassarHumano,
  motivoRepasse
);

if (hasBrunaOverride) {
  warnings.push({
    path: "bruna_override",
    result: "override_aplicado",
    reason: "guard_rail_definiu_resposta_prioritaria"
  });

  statusLead = enumValue(
    brunaOverrideRaw.status_lead || statusLead,
    [
      "NOVO_LEAD",
      "COLETANDO_DADOS",
      "QUALIFICANDO",
      "PRE_REPROVADO",
      "APTO_PARA_AVALIACAO",
      "AGUARDANDO_PAGAMENTO",
      "COMPROVANTE_RECEBIDO",
      "TRANSFERIDO_FLAVIA",
      "ENCERRADO_NAO_PERFIL",
      "ENCERRADO_SEM_RESPOSTA",
      "ENCERRADO"
    ],
    statusLead,
    warnings,
    "bruna_override.status_lead"
  );

  ultimaIntencao = enumValue(
    brunaOverrideRaw.ultima_intencao || ultimaIntencao,
    [
      "INTERESSE_CRECHE",
      "INTERESSE_HOTEL",
      "PEDIU_VALOR",
      "PEDIU_LOCALIZACAO",
      "PEDIU_VISITA",
      "INFORMOU_DADOS_CAO",
      "INFORMOU_DADOS_TUTOR",
      "ACEITOU_AVALIACAO",
      "RECEBEU_PIX",
      "ENVIOU_COMPROVANTE",
      "PEDIU_HUMANO",
      "MACHO_NAO_CASTRADO",
      "RACA_POTENCIAL_DANO",
      "URGENCIA_FERIADO",
      "OBJECAO_PRECO",
      "SUMIU"
    ],
    ultimaIntencao,
    warnings,
    "bruna_override.ultima_intencao"
  );

  eventoSistema = enumValue(
    brunaOverrideRaw.evento_sistema ?? eventoSistema,
    [
      "",
      "FORMULARIO_RECEBIDO",
      "GUIA_ENVIADO",
      "PIX_SOLICITADO",
      "ANEXO_RECEBIDO",
      "COMPROVANTE_IDENTIFICADO",
      "REPASSE_FLAVIA",
      "FOLLOWUP_DISPARADO",
      "CONVERSA_ENCERRADA"
    ],
    eventoSistema,
    warnings,
    "bruna_override.evento_sistema"
  );

  mensagensResposta = normalizeMessages(brunaOverrideRaw.mensagens_resposta);
  proximaAcao = firstFilled(brunaOverrideRaw.proxima_acao, proximaAcao);

  deveRepassarHumano = toBool(brunaOverrideRaw.deve_repassar_humano);
  motivoRepasse = deveRepassarHumano
    ? firstFilled(brunaOverrideRaw.motivo_repasse, brunaOverrideRaw.resumo_interno_repasse?.motivo, "repasse_humano")
    : "";

  deveEnviarGuia = toBool(brunaOverrideRaw.deve_enviar_guia);
  deveSolicitarPagamento = toBool(brunaOverrideRaw.deve_solicitar_pagamento);
  deveEncerrarConversa = toBool(brunaOverrideRaw.deve_encerrar_conversa);

  resumoLead = normalizeResumoLead(previousResumo, brunaOverrideRaw.resumo_lead, base, deveRepassarHumano);

  resumoInternoRepasse = normalizeResumoRepasse(
    previousRepasse,
    brunaOverrideRaw.resumo_interno_repasse,
    resumoLead,
    deveRepassarHumano,
    motivoRepasse
  );
}

function hasBlockedRace(dogs = []) {
  return dogs.some(dog => raceStatus(dog) === "bloqueado_potencial_dano");
}

const femaleWronglyBlocked =
  !hasBlockedRace(dogs) &&
  dogs.some(dog => dog.sexo === "femea") &&
  (
    ultimaIntencao === "MACHO_NAO_CASTRADO" ||
    messageLooksLikeWrongCastrationIntent(mensagensResposta)
  );

if (!hasBrunaOverride && femaleWronglyBlocked) {
  warnings.push({
    path: "castracao",
    result: "corrigido",
    reason: "femea_nao_pode_cair_em_regra_de_macho_nao_castrado"
  });

  statusLead = "QUALIFICANDO";
  ultimaIntencao = "INFORMOU_DADOS_CAO";
  eventoSistema = "";
  deveRepassarHumano = false;
  motivoRepasse = "";
  deveSolicitarPagamento = false;
  deveEncerrarConversa = false;

  const female = dogs.find(dog => dog.sexo === "femea");
  const name = dogName(female, dogs.indexOf(female));

  proximaAcao = female?.no_cio === "nao_informado"
    ? "perguntar_se_esta_no_cio"
    : "seguir_qualificacao_femea";

  mensagensResposta = [
    `${name} sendo fêmea, a castração não bloqueia automaticamente o atendimento. O ponto importante é ela não estar no cio para frequentar a rotina em grupo.`
  ];
}

const maleAdultUnknown = dogs.find(dog => isMaleAdult(dog) && dog.castrado === "nao_informado");

if (!hasBrunaOverride && maleAdultUnknown && messageLooksLikeWrongCastrationIntent(mensagensResposta)) {
  warnings.push({
    path: "castracao",
    result: "corrigido",
    reason: "macho_adulto_com_castracao_nao_informada_deve_perguntar_status_antes_de_intencao"
  });

  statusLead = "QUALIFICANDO";
  ultimaIntencao = "INFORMOU_DADOS_CAO";
  eventoSistema = "";
  deveRepassarHumano = false;
  motivoRepasse = "";
  deveSolicitarPagamento = false;
  deveEncerrarConversa = false;

  const name = dogName(maleAdultUnknown, dogs.indexOf(maleAdultUnknown));

  proximaAcao = "aguardar_confirmacao_castracao_status";
  mensagensResposta = [
    `Me confirma uma coisa importante: ${name} é castrado? Machos a partir de 8 meses precisam ser castrados para frequentar a rotina em grupo.`
  ];
}

const maleAdultCastrated = dogs.find(dog => isMaleAdult(dog) && dog.castrado === "sim");

if (!hasBrunaOverride && maleAdultCastrated && messageLooksLikeWrongCastrationIntent(mensagensResposta)) {
  warnings.push({
    path: "castracao",
    result: "corrigido",
    reason: "macho_adulto_ja_castrado_nao_deve_perguntar_intencao_de_castrar"
  });

  statusLead = "QUALIFICANDO";
  ultimaIntencao = "INFORMOU_DADOS_CAO";
  eventoSistema = "";
  deveRepassarHumano = false;
  motivoRepasse = "";
  deveSolicitarPagamento = false;
  deveEncerrarConversa = false;

  if (!sanitaryComplete(maleAdultCastrated)) {
    proximaAcao = "perguntar_dados_sanitarios";
    mensagensResposta = [
      "Perfeito, então ele já é castrado. Vacinas, antipulgas e vermifugação estão em dia?"
    ];
  } else if (!behaviorComplete(maleAdultCastrated)) {
    proximaAcao = "perguntar_comportamento_em_grupo";
    mensagensResposta = [
      "Perfeito, então ele já é castrado. Como ele costuma ficar com outros cães?"
    ];
  } else {
    proximaAcao = "seguir_qualificacao_apos_castracao_confirmada";
    mensagensResposta = [
      "Perfeito, então ele já é castrado. Com isso, dá para seguir para o próximo passo do atendimento."
    ];
  }
}

if (
  !hasBrunaOverride &&
  hasPendingRace(dogs) &&
  (
    statusLead === "ENCERRADO_NAO_PERFIL" ||
    ultimaIntencao === "RACA_POTENCIAL_DANO" ||
    eventoSistema === "CONVERSA_ENCERRADA" ||
    deveEncerrarConversa ||
    deveSolicitarPagamento ||
    messageLooksLikeBreedBlock(mensagensResposta)
  )
) {
  warnings.push({
    path: "raca",
    result: "corrigido",
    reason: "raca_pendente_nao_pode_encerrar_bloquear_ou_pedir_pagamento"
  });

  const pendingDog = getPendingRaceDog(dogs);
  const name = dogName(pendingDog, dogs.indexOf(pendingDog));
  const originalBreed = firstFilled(
    pendingDog?.raca,
    pendingDog?.regras_raca?.raca_original,
    "raça informada"
  );

  statusLead = "COLETANDO_DADOS";
  ultimaIntencao = "INFORMOU_DADOS_CAO";
  eventoSistema = "";
  deveRepassarHumano = false;
  motivoRepasse = "";
  deveSolicitarPagamento = false;
  deveEncerrarConversa = false;
  proximaAcao = "aguardar_confirmacao_raca";

  mensagensResposta = [
    `Pra eu não cadastrar errado: você confirma qual é a raça exata de ${name}? Aqui ficou como "${originalBreed}", mas preciso confirmar antes de seguir.`
  ];
}

if (!hasBrunaOverride && allDogsBlockedByRace(dogs)) {
  statusLead = "ENCERRADO_NAO_PERFIL";
  ultimaIntencao = "RACA_POTENCIAL_DANO";
  eventoSistema = "CONVERSA_ENCERRADA";
  deveRepassarHumano = false;
  motivoRepasse = "";
  deveSolicitarPagamento = false;
  deveEncerrarConversa = true;
  proximaAcao = "encerrar_por_raca_potencial_dano";

  if (!mensagensResposta.length || !messageLooksLikeBreedBlock(mensagensResposta)) {
    mensagensResposta = [
      "Entendo. Essa regra não é um julgamento sobre o cão individualmente e não significa que ele seja agressivo. É uma regra operacional de segurança da AuAu para ambiente coletivo, onde vários cães convivem juntos. Por isso, para essa raça específica, infelizmente não conseguimos seguir com creche ou hotel."
    ];
  }
}

if (
  !hasBrunaOverride &&
  (
    statusLead === "AGUARDANDO_PAGAMENTO" ||
    deveSolicitarPagamento === true ||
    messageLooksLikePaymentRequest(mensagensResposta)
  )
) {
  warnings.push({
    path: "pagamento",
    result: "bloqueado",
    reason: "bruna_nao_deve_gerar_AGUARDANDO_PAGAMENTO_nem_solicitar_pix_nessa_fase"
  });

  const paymentServiceInterest = firstFilled(
    resumoLead.servico_interesse,
    previousInputs.servico_interesse,
    previousResumo.servico_interesse
  );

  const paymentCanMarkApto =
    hasAllMinimumData(dogs) &&
    ["creche", "hotel", "creche_e_hotel"].includes(paymentServiceInterest);

  statusLead = paymentCanMarkApto ? "APTO_PARA_AVALIACAO" : "QUALIFICANDO";
  ultimaIntencao = paymentCanMarkApto ? "ACEITOU_AVALIACAO" : ultimaIntencao;
  eventoSistema = paymentCanMarkApto ? "REPASSE_FLAVIA" : "";
  deveRepassarHumano = paymentCanMarkApto;
  motivoRepasse = paymentCanMarkApto
    ? "pagamento_automatico_bloqueado_encaminhar_humano"
    : "";
  deveSolicitarPagamento = false;
  deveEncerrarConversa = false;
  proximaAcao = paymentCanMarkApto
    ? "repassar_para_humano_explicar_avaliacao_e_proximos_passos"
    : "continuar_qualificacao_sem_pagamento";

  mensagensResposta = paymentCanMarkApto
    ? [
        "Com essas informações, o próximo passo é a avaliação comportamental. Vou encaminhar para uma pessoa da equipe continuar com você em horário comercial."
      ]
    : [
        "Antes de seguir para avaliação, preciso confirmar algumas informações do cãozinho. Não vou solicitar pagamento por aqui agora."
      ];
}

const serviceInterest = firstFilled(
  resumoLead.servico_interesse,
  previousInputs.servico_interesse,
  previousResumo.servico_interesse
);

const hasServiceInterest = ["creche", "hotel", "creche_e_hotel"].includes(serviceInterest);

if (
  !hasBrunaOverride &&
  hasAllMinimumData(dogs) &&
  hasServiceInterest &&
  statusLead !== "TRANSFERIDO_FLAVIA" &&
  statusLead !== "ENCERRADO_NAO_PERFIL" &&
  statusLead !== "COMPROVANTE_RECEBIDO"
) {
  warnings.push({
    path: "apto",
    result: "repassar_humano",
    reason: "lead_apto_deve_ir_para_humano_sem_pagamento_automatico"
  });

  statusLead = "APTO_PARA_AVALIACAO";
  ultimaIntencao = ultimaIntencao || "INFORMOU_DADOS_CAO";
  eventoSistema = "REPASSE_FLAVIA";
  deveRepassarHumano = true;
  motivoRepasse = "cao_apto_para_avaliacao_repassar_humano";
  deveSolicitarPagamento = false;
  deveEncerrarConversa = false;
  proximaAcao = "repassar_para_humano_explicar_avaliacao_e_proximos_passos";

  mensagensResposta = [
    "Com essas informações, o próximo passo é a avaliação comportamental. Ela serve para a equipe entender com segurança se o cão fica bem em grupo. Vou encaminhar para uma pessoa da equipe seguir com você nos próximos passos."
  ];
}

if (messageLooksLikePriceAnswer(mensagensResposta)) {
  const pediuPrecoAgora = previousInputs.precisa_responder_preco === true;
  const currentText = clean(base.message?.content || base.chatInput || "");
  const insistiuPreco = /(mas quanto custa|queria saber o valor|valor mesmo|me passa o preco|me passa o preço|só quero saber|so quero saber|qual o valor|qual o preço|qual o preco|quanto fica então|quanto fica entao)/i.test(currentText);

  if (pediuPrecoAgora && !insistiuPreco) {
    warnings.push({
      path: "preco",
      result: "warning",
      reason: "possivel_preco_respondido_no_primeiro_pedido_sem_insistencia"
    });
  }
}

if (deveRepassarHumano) {
  eventoSistema = eventoSistema || "REPASSE_FLAVIA";
  motivoRepasse = motivoRepasse || "repasse_humano";
  resumoLead.responsavel_humano = "Flavia";
} else {
  motivoRepasse = "";
  resumoLead.responsavel_humano = "";

  if (eventoSistema === "REPASSE_FLAVIA") {
    eventoSistema = "";
  }
}

resumoLead = normalizeResumoLead(
  previousResumo,
  resumoLead,
  base,
  deveRepassarHumano
);

resumoInternoRepasse = normalizeResumoRepasse(
  previousRepasse,
  resumoInternoRepasse,
  resumoLead,
  deveRepassarHumano,
  motivoRepasse
);

if (humanoAssumiu && !hasBrunaOverride) {
  shouldReply = false;
  motivoBloqueioEnvio = "humano_assumiu";
  mensagensResposta = [];
  deveRepassarHumano = false;
  motivoRepasse = "";
  eventoSistema = "";
  proximaAcao = "nao_responder_humano_assumiu";
}

if (!mensagensResposta.length && shouldReply) {
  shouldReply = false;
  motivoBloqueioEnvio = motivoBloqueioEnvio || "sem_mensagem_resposta_valida";
}

if (unwrapped.parse_error === true && !hasBrunaOverride) {
  shouldReply = false;
  motivoBloqueioEnvio = "erro_parse_saida_bruna";
  mensagensResposta = [];
}

const aptoParaAvaliacao = enumValue(
  previousInputs.apto_para_avaliacao,
  ["sim", "nao", "caso_cinzento", "pendente"],
  statusLead === "APTO_PARA_AVALIACAO"
    ? "sim"
    : statusLead === "ENCERRADO_NAO_PERFIL"
      ? "nao"
      : "pendente",
  warnings,
  "apto_para_avaliacao"
);

const statusPagamentoAnterior = enumValue(
  previousInputs.status_pagamento,
  [
    "nao_solicitado",
    "aguardando_pagamento",
    "comprovante_recebido",
    "validacao_humana_pendente",
    "aprovado_humano",
    "negado_humano",
    "estornado",
    "cancelado"
  ],
  "nao_solicitado",
  warnings,
  "status_pagamento"
);

const statusPagamento = resumoLead.comprovante_recebido
  ? "validacao_humana_pendente"
  : deveSolicitarPagamento
    ? "aguardando_pagamento"
    : statusPagamentoAnterior === "aguardando_pagamento"
      ? "nao_solicitado"
      : statusPagamentoAnterior;

const normalizedOutput = {
  status_lead: statusLead,
  ultima_intencao: ultimaIntencao,
  evento_sistema: eventoSistema,

  mensagens_resposta: shouldReply ? mensagensResposta : [],

  resumo_lead: resumoLead,

  proxima_acao: proximaAcao,

  deve_repassar_humano: deveRepassarHumano,
  motivo_repasse: deveRepassarHumano ? motivoRepasse : "",

  deve_enviar_guia: deveEnviarGuia,
  deve_solicitar_pagamento: false,
  deve_consultar_agenda: false,
  deve_criar_pre_reserva: false,
  deve_encerrar_conversa: deveEncerrarConversa,

  resumo_interno_repasse: resumoInternoRepasse
};

const normalizedInputs = {
  ...previousInputs,

  status_lead: normalizedOutput.status_lead,
  ultima_intencao: normalizedOutput.ultima_intencao,
  evento_sistema: normalizedOutput.evento_sistema,

  apto_para_avaliacao: aptoParaAvaliacao,
  motivo_pre_reprovacao: firstFilled(previousInputs.motivo_pre_reprovacao),

  status_pagamento: statusPagamento,

  comprovante_recebido: resumoLead.comprovante_recebido === true,
  tipo_comprovante: resumoLead.tipo_comprovante || "nao_informado",
  arquivo_comprovante_referencia: resumoLead.arquivo_comprovante_referencia || "",

  pre_reserva_criada: false,
  data_hora_avaliacao: "",
  data_hora_pre_reserva: "",

  quantidade_caes: dogs.length,
  caes_json: dogs,

  resumo_lead: resumoLead,
  resumo_interno_repasse: resumoInternoRepasse,

  proxima_acao: normalizedOutput.proxima_acao,

  deve_repassar_humano: normalizedOutput.deve_repassar_humano,
  motivo_repasse: normalizedOutput.motivo_repasse,

  deve_enviar_guia: normalizedOutput.deve_enviar_guia,
  deve_solicitar_pagamento: false,
  deve_consultar_agenda: false,
  deve_criar_pre_reserva: false,
  deve_encerrar_conversa: normalizedOutput.deve_encerrar_conversa,

  mensagens_resposta: normalizedOutput.mensagens_resposta,

  bruna_system_guard: brunaSystemGuard,
  bruna_override: hasBrunaOverride ? brunaOverrideRaw : null,

  diagnostico_crm: {
    ...(isObject(previousInputs.diagnostico_crm) ? previousInputs.diagnostico_crm : {}),
    humano_assumiu: humanoAssumiu,
    humano_assumiu_por_label_ou_estado: humanoAssumiu,
    nao_usou_mensagem_humana_antiga_como_criterio: true
  }
};

delete normalizedInputs.resumo_lead.caes_json;
delete normalizedInputs.resumo_lead.quantidade_caes;
delete normalizedInputs.resumo_interno_repasse.caes_json;
delete normalizedInputs.resumo_interno_repasse.quantidade_caes;

const debugContext = {
  normaliza_bruna_version: NORMALIZA_BRUNA_VERSION,

  parse_error: unwrapped.parse_error === true,
  parse_error_message: unwrapped.raw_parsed?.__parse_error_message || "",

  should_reply: shouldReply,
  motivo_bloqueio_envio: motivoBloqueioEnvio,

  humano_assumiu: humanoAssumiu,

  bruna_override_aplicado: hasBrunaOverride,
  bruna_system_guard_aplicado: isNonEmptyObject(brunaSystemGuard),

  quantidade_caes: dogs.length,

  caes_resumo: dogs.map((dog, index) => ({
    dog_index: index,
    nome: dog.nome,
    sexo: dog.sexo,
    idade_anos: dog.idade_anos,
    idade_texto: dog.idade_texto,
    idade_meses_calculada: ageMonths(dog),
    castrado: dog.castrado,
    no_cio: dog.no_cio,
    status_raca: raceStatus(dog),
    decisao_raca_conclusiva: raceConclusive(dog),
    macho_adulto: isMaleAdult(dog)
  })),

  safeguards: {
    femea_bloqueio_macho_corrigido: femaleWronglyBlocked,
    bloqueou_pagamento_automatico: warnings.some(w => w.path === "pagamento"),
    corrigiu_macho_adulto_castracao_desconhecida: warnings.some(w => w.reason === "macho_adulto_com_castracao_nao_informada_deve_perguntar_status_antes_de_intencao"),
    corrigiu_macho_ja_castrado: warnings.some(w => w.reason === "macho_adulto_ja_castrado_nao_deve_perguntar_intencao_de_castrar"),
    bloqueou_raca_pendente: warnings.some(w => w.path === "raca"),
    repasse_apto_humano: warnings.some(w => w.path === "apto")
  },

  warnings
};

return [
  {
    json: {
      normaliza_bruna_version: NORMALIZA_BRUNA_VERSION,
      inputs: normalizedInputs,

      message: base.message || {},
      chatwoot: base.chatwoot || {},
      lead: base.lead || {},
      memory: cleanMemory(base.memory),

      config_bruna: base.config_bruna || {},

      agent_name: base.agent_name || "Bruna",

      should_reply: shouldReply,
      motivo_bloqueio_envio: motivoBloqueioEnvio,

      chatOutput: shouldReply ? normalizedOutput.mensagens_resposta.join("\n\n") : "",

      output_bruna: normalizedOutput,

      bruna_system_guard: brunaSystemGuard,
      bruna_override: hasBrunaOverride ? brunaOverrideRaw : null,

      raw_bruna_output: rawOutput,

      debug_context: debugContext
    }
  }
];

