const MONTA_CONTEXTO_BRUNA_VERSION = "v7_2_repasse_exige_motivo_debug";

function parseMaybeJson(value, fallback) {
  if (value === undefined || value === null || value === "") return fallback;
  if (typeof value === "object") return value;

  const text = String(value || "").trim();

  try {
    return JSON.parse(text);
  } catch (e) {
    const arrayMatch = text.match(/\[[\s\S]*\]/);
    if (arrayMatch) {
      try {
        return JSON.parse(arrayMatch[0]);
      } catch (e2) {}
    }

    const objectMatch = text.match(/\{[\s\S]*\}/);
    if (objectMatch) {
      try {
        return JSON.parse(objectMatch[0]);
      } catch (e3) {}
    }
  }

  return fallback;
}

function firstItem(nodeName) {
  try {
    return $(nodeName).first().json || {};
  } catch (e) {
    return {};
  }
}

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function asObject(value) {
  return isObject(value) ? value : {};
}

function cleanString(value) {
  if (value === undefined || value === null) return "";
  return String(value).trim();
}

function firstFilled(...values) {
  for (const value of values) {
    const text = cleanString(value);
    if (text) return text;
  }

  return "";
}

function firstFilledOr(fallback, ...values) {
  const value = firstFilled(...values);
  return value ? value : fallback;
}

function toBool(value) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1) return true;
  if (value === 0) return false;

  const text = String(value || "").trim().toLowerCase();

  if (["1", "true", "sim", "yes", "t"].includes(text)) return true;
  if (["0", "false", "nao", "não", "no", "f"].includes(text)) return false;

  return false;
}

function firstBool(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== "") {
      return toBool(value);
    }
  }

  return false;
}

function normalizeEnum(value, allowed, fallback) {
  const v = cleanString(value);
  return allowed.includes(v) ? v : fallback;
}

function publicFacingText(value) {
  return String(value || "")
    .replace(/\s{2,}/g, " ")
    .trim();
}

function normalizeText(value) {
  return publicFacingText(value)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function publicFacingObject(value) {
  if (Array.isArray(value)) {
    return value.map(publicFacingObject);
  }

  if (isObject(value)) {
    const out = {};

    for (const [key, item] of Object.entries(value)) {
      out[key] = publicFacingObject(item);
    }

    return out;
  }

  if (typeof value === "string") {
    return publicFacingText(value);
  }

  return value;
}

function redactSensitiveConfig(value) {
  const blockedKeys = new Set([
    "pix_tipo",
    "pix_chave",
    "pix_recebedor",
    "chave_pix",
    "tipo_pix",
    "recebedor",
    "cnpj",
    "cpf",
    "dados_bancarios",
    "dados_bancários",
    "banco",
    "agencia",
    "agência"
  ]);

  if (Array.isArray(value)) {
    return value.map(redactSensitiveConfig);
  }

  if (isObject(value)) {
    const out = {};

    for (const [key, item] of Object.entries(value)) {
      const normalizedKey = String(key || "")
        .toLowerCase()
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "")
        .trim();

      if (blockedKeys.has(normalizedKey)) continue;

      if (
        normalizedKey.includes("cnpj") ||
        normalizedKey.includes("cpf") ||
        normalizedKey.includes("recebedor") ||
        normalizedKey.includes("dados_bancarios") ||
        normalizedKey.includes("banco") ||
        normalizedKey.includes("agencia") ||
        /(chave_pix|pix_chave|pix_recebedor|tipo_pix|conta_bancaria|conta_corrente|numero_conta|nro_conta)/.test(normalizedKey)
      ) {
        continue;
      }

      out[key] = redactSensitiveConfig(item);
    }

    return out;
  }

  if (typeof value === "string") {
    const textNorm = normalizeText(value);

    if (
      textNorm.includes("chave pix") ||
      textNorm.includes("cpf") ||
      textNorm.includes("cnpj") ||
      textNorm.includes("recebedor") ||
      textNorm.includes("dados bancarios") ||
      textNorm.includes("agencia") ||
      textNorm.includes("conta bancaria") ||
      textNorm.includes("conta corrente") ||
      textNorm.includes("numero conta") ||
      textNorm.includes("nro conta")
    ) {
      return "";
    }
  }

  return value;
}

function getPath(obj, path) {
  if (!isObject(obj)) return "";

  const parts = String(path || "").split(".");
  let current = obj;

  for (const part of parts) {
    if (!isObject(current) && !Array.isArray(current)) return "";
    current = current?.[part];

    if (current === undefined || current === null) return "";
  }

  return current;
}

