    vacinas_ok: "nao_informado",
    antipulgas_ok: "nao_informado",
    vermifugacao_ok: "nao_informado",
    perfil_comportamental: "nao_informado",
    comportamento_observacoes: "",
    possui_relatorio_veterinario: "nao_informado",
    observacoes: "",
    regras_raca: {}
  };
}



function normalizeDog(dog = {}) {
  const out = {
    ...emptyDog(),

    nome: publicFacingText(dog.nome),
    idade_anos: cleanText(dog.idade_anos),
    idade_texto: publicFacingText(dog.idade_texto),
    raca: publicFacingText(dog.raca),
    raca_canonica: publicFacingText(dog.raca_canonica),

    porte: normalizeEnum(
      dog.porte,
      ["mini", "pequeno", "medio", "grande", "gigante", "nao_definido"],
      "nao_definido"
    ),

    sexo: normalizeEnum(
      dog.sexo,
      ["macho", "femea", "nao_informado"],
      "nao_informado"
    ),

    castrado: normalizeEnum(
      dog.castrado,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    no_cio: normalizeEnum(
      dog.no_cio,
      ["sim", "nao", "nao_se_aplica", "nao_informado"],
      "nao_informado"
    ),

    vacinas_ok: normalizeEnum(
      dog.vacinas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    antipulgas_ok: normalizeEnum(
      dog.antipulgas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    vermifugacao_ok: normalizeEnum(
      dog.vermifugacao_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    perfil_comportamental: normalizeEnum(
      dog.perfil_comportamental,
      [
        "nao_informado",
        "tranquilo",
        "sociavel",
        "seletivo",
        "reativo_leve",
        "reativo_alto",
        "agressivo",
        "indeterminado"
      ],
      "nao_informado"
    ),

    comportamento_observacoes: publicFacingText(dog.comportamento_observacoes),

    possui_relatorio_veterinario: normalizeEnum(
      dog.possui_relatorio_veterinario,
      ["sim", "nao", "nao_se_aplica", "nao_informado"],
      "nao_informado"
    ),

    observacoes: publicFacingText(dog.observacoes),

    regras_raca: isObject(dog.regras_raca) ? dog.regras_raca : {}
  };

  if (out.sexo === "macho") {
    out.no_cio = "nao_se_aplica";
  }

  return out;
}

function hasDogIdentity(dog = {}) {
  return Boolean(
    meaningful(dog.nome) ||
    meaningful(dog.raca) ||
    meaningful(dog.raca_canonica) ||
    meaningful(dog.idade_anos) ||
    meaningful(dog.idade_texto) ||
    ["macho", "femea"].includes(cleanText(dog.sexo))
  );
}

function normalizeDogs(value) {
  const parsed = parseMaybeJson(value, []);
  if (!Array.isArray(parsed)) return [];

  return parsed
    .filter(dog => isObject(dog))
    .map(normalizeDog)
    .filter(dog => hasDogIdentity(dog));
}

function normalizeDogPatches(value) {
  const parsed = parseMaybeJson(value, []);
  if (!Array.isArray(parsed)) return [];

  return parsed
    .filter(dog => isObject(dog))
    .map(normalizeDog)
    .filter(dog => hasDogIdentity(dog) || dogPatchHasComplementaryData(dog));
}

function dogHasAttributeSignalInText(text) {
  const t = norm(text);

  return (
    /\b\d{1,2}\s*(anos?|mes(?:es)?)\b/.test(t) ||
    /\b(macho|femea|fêmea|cadela|cadelinha|machinho)\b/.test(t) ||
    /(castrad|cio|porte|raca|raça)/.test(t) ||
    /(vacina|antipulga|vermifug)/.test(t) ||
    /(convive|comport|sociav|reativ|agressiv|morde|late)/.test(t)
  );
}

function knownDogNameInText(text, dogs = []) {
  const t = norm(text);

  return dogs.some(dog => {
    const name = norm(dog.nome || "");
    return name && t.includes(name);
  });
}

function lastQuestionText(ctx = {}) {
  return publicFacingText(
    ctx.message?.last_bruna_question_before_current_block ||
    ctx.message?.last_bruna_message_before_current_block ||
    ""
  );
}

function lastQuestionAskedFrequency(ctx) {
  const lastQuestion = norm(lastQuestionText(ctx));

  return /(frequencia|frequência|quantas vezes|vezes por semana|dias por semana|trazer.*semana|creche.*semana)/.test(lastQuestion);
}

function lastQuestionAskedCastration(ctx) {
  const lastQuestion = norm(lastQuestionText(ctx));

  return /(pretende castrar|vai castrar|tem intencao de castrar|tem intenção de castrar|pretende fazer a castracao|pretende fazer a castração)/.test(lastQuestion);
}

function lastQuestionAskedHuman(ctx) {
  const lastQuestion = norm(lastQuestionText(ctx));

  return /(quer que eu chame|chamar uma pessoa|pessoa da equipe|atendimento humano|falar com alguem|falar com alguém)/.test(lastQuestion);
}

function lastQuestionAskedFinalHelp(ctx) {
  const lastQuestion = norm(lastQuestionText(ctx));

  return /(posso ajudar com mais alguma informacao|posso ajudar com mais alguma informação|precisa de mais alguma coisa|te ajudo com mais alguma coisa|ficou alguma duvida|ficou alguma dúvida)/.test(lastQuestion);
}

function lastQuestionAskedSanitary(ctx = {}) {
  const lastQuestion = norm(lastQuestionText(ctx));
  const action = norm(ctx.inputs?.proxima_acao || "");

  return (
    /(sanitario|sanitarios|sanitaria|sanitarias)/.test(action) ||
    /(vacina|vacinas|antipulga|antipulgas|vermifug)/.test(lastQuestion)
  );
}

function lastQuestionAskedBehavior(ctx = {}) {
  const lastQuestion = norm(lastQuestionText(ctx));
  const action = norm(ctx.inputs?.proxima_acao || "");

  return (
    /(comportamento|rotina|convivencia|convivência|socializacao|socialização)/.test(action) ||
    /(rotina|comportamento|convive|convivencia|convivência|outros caes|outros cães|fica com outros|costuma ficar com outros|sociavel|sociável)/.test(lastQuestion)
  );
}

function inferBehaviorPatchFromContext(text, ctx = {}) {
  if (!lastQuestionAskedBehavior(ctx)) return {};

  const t = norm(text);

  if (!t) return {};
  if (hasQuestionSignal(text)) return {};
  if (looksLikeCommercialOrRouting(text)) return {};

  if (/(convive bem|se da (bem|super bem|muito bem)|fica bem com outros|gosta de outros|brinca com outros|sociavel|tranquilo)/.test(t)) {
    return {
      perfil_comportamental: "sociavel",
      comportamento_observacoes: publicFacingText(text)
    };
  }

  if (/(nao sei|não sei|nunca teve contato|nao convive|não convive|não teve contato|nao teve contato)/.test(t)) {
    return {
      perfil_comportamental: "indeterminado",
      comportamento_observacoes: publicFacingText(text)
    };
  }

  if (/(reativ|agressiv|morde|avanca|avança|briga|late muito)/.test(t)) {
    return {
      perfil_comportamental: "indeterminado",
      comportamento_observacoes: publicFacingText(text)
    };
  }

  return {};
}

function getTurnContext(ctx = {}, dogs = []) {
  const action = norm(ctx.inputs?.proxima_acao || "");
  const lastQuestion = norm(lastQuestionText(ctx));
  const contextText = `${action} ${lastQuestion}`;

  if (
    /(sanitario|sanitarios|sanitaria|sanitarias)/.test(action) ||
    /(vacina|vacinas|antipulga|antipulgas|vermifug)/.test(lastQuestion)
  ) {
    return "sanitario";
  }

  if (
    /(confirmacao_castracao_status|confirmar_castracao_status|aguardar_confirmacao_castracao_status)/.test(action) ||
    (
      /(e castrado|eh castrado|é castrado|e castrada|eh castrada|é castrada|me confirma.*castrad)/.test(lastQuestion) &&
      !/(pretende|vai|intencao|intenção)/.test(lastQuestion)
    )
  ) {
    return "castracao_status";
  }

  if (lastQuestionAskedCastration(ctx)) {
    return "castracao_intencao";
  }

  if (lastQuestionAskedFrequency(ctx)) {
    return "frequencia";
  }

  if (lastQuestionAskedHuman(ctx)) {
    return "humano";
  }

  if (lastQuestionAskedFinalHelp(ctx)) {
    return "finalizacao";
  }

  if (/(hotel|hospedagem|periodo|período|diaria|diária|checkin|check in|checkout|check out)/.test(contextText)) {
    return "hotel_periodo";
  }

  if (isBreedConfirmationState(ctx, dogs)) {
    return "raca";
  }

  return "geral";
}

function hasNegativeOrUncertainSignal(text) {
  const t = norm(text);

  return /\b(nao|não|n|negativo|falta|faltando|pendente|atrasad|vencid|preciso ver|vou ver|nao sei|não sei|acho que nao|acho que não|talvez|duvida|dúvida)\b/.test(t);
}

function hasQuestionSignal(text) {
  const t = norm(text);

  return (
    /\?/.test(String(text || "")) ||
    /\b(como|qual|quais|onde|quando|por que|porque)\b/.test(t)
  );
}

function looksLikeCommercialOrRouting(text) {
  const t = norm(text);

  return /(preco|preço|valor|quanto|hotel|creche|diaria|diária|humano|atendente|visita|endereco|endereço|localizacao|localização)/.test(t);
}

function inferSanitaryFromContext(text, ctx = {}, dogs = []) {
  if (getTurnContext(ctx, dogs) !== "sanitario") return {};

  const t = norm(text);

  if (!t) return {};
  if (hasNegativeOrUncertainSignal(text)) return {};
  if (hasQuestionSignal(text)) return {};
  if (looksLikeCommercialOrRouting(text)) return {};

  return {
    vacinas_ok: "sim",
    antipulgas_ok: "sim",
    vermifugacao_ok: "sim"
  };
}

function textIsBadBreedAnswer(text) {
  const t = norm(text);

  if (!t) return true;
  if (hasNegativeOrUncertainSignal(text)) return true;
  if (hasQuestionSignal(text)) return true;
  if (looksLikeCommercialOrRouting(text)) return true;
  if (isFrequencyOnlyText(text, {}, [])) return true;
  if (parseHotelPeriodDays(text)) return true;

  if (/(vacina|vacinas|antipulga|antipulgas|vermifug|tudo em dia|tudo certo)/.test(t)) return true;
  if (/^\d+$/.test(t)) return true;
  if (/\d{1,2}\s*(anos?|mes(?:es)?)\b/.test(t)) return true;

  return false;
}

function canAcceptBreedFromExtractor(dog = {}, currentText = "", ctx = {}, caesAtuais = [], structuredDog = null) {
  const raca = publicFacingText(dog.raca || dog.raca_canonica || "");
  if (!meaningful(raca)) return true;

  if (structuredDog && norm(structuredDog.raca) && norm(structuredDog.raca) === norm(raca)) {
    return true;
  }

  if (isBreedConfirmationState(ctx, caesAtuais) && !textIsBadBreedAnswer(raca)) {
    return true;
  }

  return false;
}

function sanitizeBreedFieldsFromExtractor(dogs = [], currentText = "", ctx = {}, caesAtuais = [], structuredDog = null) {
  return normalizeDogPatches(dogs).map(dog => {
    if (!canAcceptBreedFromExtractor(dog, currentText, ctx, caesAtuais, structuredDog)) {
      return normalizeDog({
        ...dog,
        raca: "",
        raca_canonica: "",
        regras_raca: {}
      });
    }

    return dog;
  }).filter(dog => hasDogIdentity(dog) || dogPatchHasComplementaryData(dog));
}

function applySanitaryPatchToDogs(caesAtuais = [], caesPatch = [], sanitaryPatch = {}) {
  if (!Object.keys(sanitaryPatch || {}).length) return normalizeDogs(caesPatch);

  const patchDogs = normalizeDogPatches(caesPatch);

  if (patchDogs.length) {
    return patchDogs.map(dog => normalizeDog({
      ...dog,
      ...sanitaryPatch,
      regras_raca: dog.regras_raca || {}
    }));
  }

  const currentDogs = normalizeDogs(caesAtuais);

  if (!currentDogs.length) return [];

  return currentDogs.map(dog => normalizeDog({
    ...dog,
    ...sanitaryPatch,
    regras_raca: dog.regras_raca || {}
  }));
}

function normalizeFrequencyText(text, ctx = {}) {
  const t = norm(text);
  const askedFrequency = lastQuestionAskedFrequency(ctx);

  if (/(^1x\b|uma vez|1 vez)/.test(t)) return "1x por semana";
  if (/(^2x\b|duas vezes|2 vezes|segunda e quinta)/.test(t)) return "2x por semana";
  if (/(^3x\b|tres vezes|três vezes|3 vezes|segunda quarta e sexta|segunda, quarta e sexta)/.test(t)) return "3x por semana";
  if (/(^4x\b|quatro vezes|4 vezes|segunda a quinta)/.test(t)) return "4x por semana";
  if (/(^5x\b|cinco vezes|5 vezes|segunda a sexta|todos os dias|todo dia)/.test(t)) return "5x por semana";

  if (askedFrequency) {
    if (/^(1|um|uma)$/.test(t)) return "1x por semana";
    if (/^(2|dois|duas)$/.test(t)) return "2x por semana";
    if (/^(3|tres|três)$/.test(t)) return "3x por semana";
    if (/^(4|quatro)$/.test(t)) return "4x por semana";
    if (/^(5|cinco)$/.test(t)) return "5x por semana";
  }

  return "";
}

function isFrequencyOnlyText(text, ctx = {}, dogs = []) {
  const t = norm(text);
  const frequency = normalizeFrequencyText(text, ctx);

  if (!frequency) return false;
  if (dogHasAttributeSignalInText(text)) return false;

  const allowed = /^(\d+x|\d|um|uma|dois|duas|tres|três|quatro|cinco|uma vez|duas vezes|tres vezes|três vezes|quatro vezes|cinco vezes|todos os dias|todo dia|toda semana|semanal)(\s+por semana)?$/i;

  if (allowed.test(t)) return true;

  if (lastQuestionAskedFrequency(ctx) && /^(1|2|3|4|5|um|uma|dois|duas|tres|três|quatro|cinco)$/.test(t)) {
    return true;
  }

  if (knownDogNameInText(text, dogs) && frequency && !dogHasAttributeSignalInText(text)) {
    return true;
  }

  return false;
}

function parseHotelPeriodDays(text) {
  const t = norm(text);
  const m = t.match(/(?:de\s*)?(\d{1,2})\s*a\s*(\d{1,2})/);

  if (!m) return null;

  const start = Number(m[1]);
  const end = Number(m[2]);

  if (!Number.isFinite(start) || !Number.isFinite(end)) return null;
  if (start <= 0 || end <= 0 || end <= start) return null;

  return {
    start_day: start,
    end_day: end,
    diarias: end - start
  };
}

function isHotelPeriodText(text) {
  const t = norm(text);

  return /(\d{1,2}\s*a\s*\d{1,2}|de\s*\d{1,2}\s*a\s*\d{1,2}|checkin|check in|checkout|check out|hospedagem|hotel|feriado|sao joao|são joão|janeiro|fevereiro|marco|março|abril|maio|junho|julho|agosto|setembro|outubro|novembro|dezembro)/.test(t);
}

function isHotelPeriodOnlyText(text, dogs = []) {
  if (!isHotelPeriodText(text)) return false;
  if (dogHasAttributeSignalInText(text)) return false;

  const t = norm(text);

  if (parseHotelPeriodDays(text)) return true;

  if (/(checkin|check in|checkout|check out|hospedagem|hotel|feriado|sao joao|são joão)/.test(t) && !knownDogNameInText(text, dogs)) {
    return true;
  }

  return false;
}

function messageAskedPrice(text) {
  const t = norm(text);

  return /(preco|preço|valor|mensalidade|diaria|diária|pacote|plano|quanto custa|quanto fica|quanto sai|valores)/.test(t);
}

function messageIsStrongPriceInsistence(text) {
  const t = norm(text);

  return /(mas quanto|so quero saber|só quero saber|me passa o preco|me passa o preço|me passa o valor|qual o valor mesmo|valor mesmo|quanto fica entao|quanto fica então|e o preco|e o preço|e o valor|queria saber o valor mesmo)/.test(t);
}

function isPriceOnlyText(text) {
  const t = norm(text);

  if (!messageAskedPrice(text)) return false;
  if (dogHasAttributeSignalInText(text)) return false;

  return /(preco|preço|valor|mensalidade|diaria|diária|pacote|plano|quanto custa|quanto fica|quanto sai|valores)/.test(t);
}

function isShortReplyOnly(text) {
  const t = norm(text);

  return /^(sim|s|nao|não|n|ok|certo|isso|confirmo|pode ser|nao sei|não sei|talvez|obrigado|obrigada|nao obrigado|não obrigado|nao obrigada|não obrigada|por enquanto nao|por enquanto não|sem mais)$/i.test(t);
}

function isYesText(text) {
  const t = norm(text);
  return /^(sim|s|isso|confirmo|correto|pode ser|pretendo|vou sim|quero sim|claro)$/i.test(t);
}

function isNoText(text) {
  const t = norm(text);
  return /^(nao|não|n|nao pretendo|não pretendo|nao vou|não vou)$/i.test(t);
}

function isFinalThanksText(text) {
  const t = norm(text);

  return /^(nao obrigado|não obrigado|nao obrigada|não obrigada|obrigado|obrigada|sem mais|nao preciso|não preciso|por enquanto nao|por enquanto não)$/i.test(t);
}

function dogKey(dog = {}) {
  const nome = norm(dog.nome);
  const raca = norm(dog.raca_canonica || dog.raca);
  const idade = norm(dog.idade_anos || dog.idade_texto);
  const sexo = norm(dog.sexo);

  if (nome) return `nome:${nome}`;

  return [
    `raca:${raca}`,
    `idade:${idade}`,
    `sexo:${sexo}`
  ].join("|");
}

function mergeDog(base = {}, patch = {}) {
  const out = normalizeDog(base);
  const incoming = normalizeDog(patch);

  const fields = [
    "nome",
    "idade_anos",
    "idade_texto",
    "raca",
    "raca_canonica",
    "porte",
    "sexo",
    "castrado",
    "no_cio",
    "vacinas_ok",
    "antipulgas_ok",
    "vermifugacao_ok",
    "perfil_comportamental",
    "comportamento_observacoes",
    "possui_relatorio_veterinario",
    "observacoes"
  ];

  for (const field of fields) {
    const next = incoming[field];
    const current = out[field];

    if (!meaningful(next)) continue;

    if (!meaningful(current)) {
      out[field] = next;
      continue;
    }

    if (
      [
        "nome",
        "idade_anos",
        "idade_texto",
        "raca",
        "raca_canonica",
        "porte",
        "sexo",
        "castrado",
        "no_cio",
        "vacinas_ok",
        "antipulgas_ok",
        "vermifugacao_ok",
        "perfil_comportamental",
        "possui_relatorio_veterinario"
      ].includes(field)
    ) {
      out[field] = next;
    }

    if (field === "comportamento_observacoes" || field === "observacoes") {
      out[field] = next;
    }
  }

  const incomingRace = norm(incoming.raca);
  const currentRace = norm(base.raca);

  const raceChanged = Boolean(
    incomingRace &&
    incomingRace !== currentRace
  );

  if (raceChanged) {
    out.raca_canonica = "";
    out.regras_raca = {};
  } else {
    out.regras_raca = isObject(base.regras_raca) ? base.regras_raca : {};
  }

  return normalizeDog(out);
}

function mergeDogs(baseDogs = [], patchDogs = []) {
  const base = normalizeDogs(baseDogs);
  const patch = normalizeDogPatches(patchDogs);

  if (!patch.length) return base;

  // Se não existe cão conhecido, patch complementar sem identidade não pode criar cão novo.
  if (!base.length) {
    return patch
      .filter(hasDogIdentity)
      .map(dog => ({ ...dog, regras_raca: {} }));
  }

  const result = [...base];
  const index = new Map();

  result.forEach((dog, i) => {
    index.set(dogKey(dog), i);
  });

  for (const dog of patch) {
    const temIdentidade = hasDogIdentity(dog);
    const temDadoComplementar = dogPatchHasComplementaryData(dog);

    // Patch complementar sem identidade só pode ser aplicado quando há um único cão conhecido.
    if (!temIdentidade && temDadoComplementar) {
      if (result.length === 1 && patch.length === 1) {
        result[0] = mergeDog(result[0], dog);
      }

      continue;
    }

    if (!temIdentidade) continue;

    const key = dogKey(dog);

    if (index.has(key)) {
      const pos = index.get(key);
      result[pos] = mergeDog(result[pos], dog);
      continue;
    }

    if (result.length === 1 && patch.length === 1) {
      result[0] = mergeDog(result[0], dog);
      continue;
    }

    index.set(key, result.length);
    result.push({ ...dog, regras_raca: {} });
  }

  return result.map(normalizeDog);
}

function unwrapExtractor(raw) {
  let parsed = parseMaybeJson(raw, {});

  if (typeof parsed.text === "string") {
    parsed = parseMaybeJson(parsed.text, {});
  }

  if (typeof parsed.output === "string") {
    parsed = parseMaybeJson(parsed.output, {});
  }

  if (isObject(parsed.output)) {
    parsed = {
      ...parsed,
      ...parsed.output
    };
    delete parsed.output;
  }

  return isObject(parsed) ? parsed : {};
}

function applyResumoPatch(resumoAtual = {}, patch = {}) {
  const resumo = isObject(resumoAtual) ? { ...resumoAtual } : {};
  const p = isObject(patch) ? patch : {};

  const fields = [
    "servico_interesse",
    "periodo_desejado",
    "data_desejada",
    "data_checkin_desejada",
    "data_checkout_desejada",
    "observacoes"
  ];

  for (const field of fields) {
    if (meaningful(p[field])) {
      resumo[field] = publicFacingText(p[field]);
    }
  }

  delete resumo.caes_json;
  delete resumo.quantidade_caes;

  return resumo;
}

function normalizeSearchValue(value) {
  const text = publicFacingText(value);

  if (!text) return "";

  const normalized = norm(text);

  if (
    normalized === "nao_informado" ||
    normalized === "nao informado" ||
    normalized === "não informado" ||
    normalized === "indefinido" ||
    normalized === "nao_definido" ||
    normalized === "não definido"
  ) {
    return "";
  }

  return text;
}

function normalizeDogForBreedLookup(dog = {}, index = 0) {
  const raca = normalizeSearchValue(dog.raca);
  const racaCanonica = normalizeSearchValue(dog.raca_canonica);
  const racaBusca = racaCanonica || raca;

  return {
    dog_index: index,
    nome: publicFacingText(dog.nome),
    idade_anos: cleanText(dog.idade_anos),
    idade_texto: publicFacingText(dog.idade_texto),

    raca,
    raca_canonica: racaCanonica,
    raca_busca: racaBusca,

    porte: cleanText(dog.porte) || "nao_definido",
    sexo: cleanText(dog.sexo) || "nao_informado",
    castrado: cleanText(dog.castrado) || "nao_informado",
    no_cio: cleanText(dog.no_cio) || "nao_informado",
    vacinas_ok: cleanText(dog.vacinas_ok) || "nao_informado",
    antipulgas_ok: cleanText(dog.antipulgas_ok) || "nao_informado",
    vermifugacao_ok: cleanText(dog.vermifugacao_ok) || "nao_informado",
    perfil_comportamental: cleanText(dog.perfil_comportamental) || "nao_informado",
    comportamento_observacoes: publicFacingText(dog.comportamento_observacoes),
    possui_relatorio_veterinario: cleanText(dog.possui_relatorio_veterinario) || "nao_informado",
    observacoes: publicFacingText(dog.observacoes)
  };
}

function normalizeDogsForBreedLookup(value) {
  const dogs = normalizeDogs(value);
  return dogs.map((dog, index) => normalizeDogForBreedLookup(dog, index));
}

function cleanResumoLead(value = {}) {
  const resumo = isObject(value) ? { ...value } : {};

  delete resumo.caes_json;
  delete resumo.quantidade_caes;

  return resumo;
}

function hasPendingBreedConfirmation(dog = {}) {
  const regra = isObject(dog.regras_raca) ? dog.regras_raca : {};

  return (
    regra.status_raca === "precisa_confirmar_raca" ||
    regra.deve_confirmar_raca === true ||
    regra.precisa_confirmacao_antes_decisao === true ||
    regra.nivel_confianca_raca === "baixa"
  );
}

function isBreedConfirmationState(ctx, dogs = []) {
  const action = norm(ctx.inputs?.proxima_acao || "");

  if (
    action === "aguardar_confirmacao_raca" ||
    action === "confirmar_raca" ||
    action === "confirmar_raca_ambigua"
  ) {
    return true;
  }

  return dogs.some(hasPendingBreedConfirmation);
}

function isShortUsefulBreedReply(text) {
  const value = norm(text);
  if (!value) return false;

  if (textIsBadBreedAnswer(text)) return false;

  const words = value.split(/\s+/).filter(Boolean);

  if (words.length < 1 || words.length > 4) return false;
  if (value.length > 50) return false;

  return true;
}

function getPendingBreedDogIndex(dogs = []) {
  const pendingIndexes = dogs
    .map((dog, index) => ({ dog, index }))
    .filter(item => hasPendingBreedConfirmation(item.dog));

  if (pendingIndexes.length === 1) {
    return pendingIndexes[0].index;
  }

  if (dogs.length === 1) {
    return 0;
  }

  return -1;
}

function buildBreedConfirmationPatch(ctx, caesAtuais, caesPatch) {
  const currentText = publicFacingText(ctx.message?.content || ctx.chatInput || "");

  if (!isBreedConfirmationState(ctx, caesAtuais)) return caesPatch;
  if (!isShortUsefulBreedReply(currentText)) return caesPatch;
  if (textIsBadBreedAnswer(currentText)) return caesPatch;

  const dogIndex = getPendingBreedDogIndex(caesAtuais);
  if (dogIndex < 0) return caesPatch;

  const dog = caesAtuais[dogIndex] || {};
  const regra = isObject(dog.regras_raca) ? dog.regras_raca : {};

  const baseRace = publicFacingText(regra.raca_original || dog.raca || "");
  if (!baseRace) return caesPatch;

  const currentNorm = norm(currentText);
  const baseNorm = norm(baseRace);

  const currentLooksComplete =
    currentNorm.split(/\s+/).filter(Boolean).length >= 2 ||
    currentNorm.includes(baseNorm);

  const composedRace = currentLooksComplete
    ? currentText
    : `${baseRace} ${currentText}`.trim();

  const patchDog = {
    ...dog,
    raca: composedRace,
    raca_canonica: "",
    regras_raca: {},
    observacoes: publicFacingText(
      [dog.observacoes, `Confirmação de raça recebida: ${currentText}`]
        .filter(Boolean)
        .join(" | ")
    )
  };

  const normalizedPatch = normalizeDogs(caesPatch);

  if (normalizedPatch.length) {
    const result = [...normalizedPatch];

    const targetIndex = normalizedPatch.length > dogIndex
      ? dogIndex
      : 0;

    result[targetIndex] = {
      ...result[targetIndex],
      ...patchDog
    };

    return result;
  }

  return [patchDog];

}

function isCastratedYesText(text) {
  const t = norm(text);

  if (!t) return false;

  if (/(nao|não)\s+(e|eh|é)?\s*castrad/.test(t)) return false;
  if (/ainda\s+(nao|não).{0,12}castrad/.test(t)) return false;
  if (/(nao|não)\s+foi\s+castrad/.test(t)) return false;

  return /(^|\s)(e|eh|é|ja e|já é|ja eh|já eh|ele e|ele é|ela e|ela é|sim e|sim é|sim eh).{0,12}castrad|castrad[oa]\s+sim|ja\s+castrad|já\s+castrad/.test(t);
}

function isCastratedNoText(text) {
  const t = norm(text);

  if (!t) return false;

  return /((nao|não)\s+(e|eh|é)?\s*castrad|(nao|não)\s+castrad|ainda\s+(nao|não).{0,12}castrad|(nao|não)\s+foi\s+castrad)/.test(t);
}

function isExplicitNoIntentionToCastrate(text) {
  const t = norm(text);

  return /((nao|não)\s+pretendo\s+castrar|(nao|não)\s+vou\s+castrar|(nao|não)\s+quero\s+castrar|(nao|não)\s+tenho\s+intencao\s+de\s+castrar|(nao|não)\s+tenho\s+intenção\s+de\s+castrar)/.test(t);
}

function isExplicitYesIntentionToCastrate(text) {
  const t = norm(text);

  return /(pretendo\s+castrar|vou\s+castrar|quero\s+castrar|tenho\s+intencao\s+de\s+castrar|tenho\s+intenção\s+de\s+castrar)/.test(t);
}

function buildCastrationStatusPatch(caesAtuais = [], status = "nao_informado") {
  const dogs = normalizeDogs(caesAtuais);

  if (!dogs.length) return [];

  if (dogs.length === 1) {
    return [
      normalizeDog({
        ...dogs[0],
        castrado: status,
        regras_raca: dogs[0].regras_raca || {}
      })
    ];
  }

  return [];
}

function titleCaseName(value) {
  const raw = publicFacingText(value);
  if (!raw) return "";

  return raw
    .toLowerCase()
    .split(/\s+/)
    .filter(Boolean)
    .map(part => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ");
}

function ageInMonths(dog = {}) {
  const idadeAnos = cleanText(dog.idade_anos);
  const idadeTexto = norm(dog.idade_texto || "");

  if (idadeAnos && /^\d+(?:[\.,]\d+)?$/.test(idadeAnos)) {
    return Math.round(Number(idadeAnos.replace(",", ".")) * 12);
  }

  const anosMatch = idadeTexto.match(/(\d{1,2})\s*anos?/);
  if (anosMatch) return Number(anosMatch[1]) * 12;

  const mesesMatch = idadeTexto.match(/(\d{1,2})\s*mes(?:es)?/);
  if (mesesMatch) return Number(mesesMatch[1]);

  return null;
}

function dogHasAdultMaleNonCastrated(dog = {}) {
  const meses = ageInMonths(dog);

  return (
    cleanText(dog.sexo) === "macho" &&
    meses !== null &&
    meses >= 8 &&
    cleanText(dog.castrado) === "nao"
  );
}

function hasAdultMaleNonCastrated(dogs = []) {
  return normalizeDogs(dogs).some(dogHasAdultMaleNonCastrated);
}

function hasFemaleNonCastrated(dogs = []) {
  return normalizeDogs(dogs).some(dog => {
    return cleanText(dog.sexo) === "femea" && cleanText(dog.castrado) === "nao";
  });
}

function detectSexFromText(text) {
  const t = norm(text);

  if (/\b(femea|fêmea|cadela|cadelinha|ela)\b/.test(t)) return "femea";
  if (/\b(macho|machinho|ele)\b/.test(t)) return "macho";

  return "nao_informado";
}

function detectCastrationFromText(text) {
  if (isCastratedNoText(text)) return "nao";
  if (isCastratedYesText(text)) return "sim";
  return "nao_informado";
}

function extractAgeFromText(text) {
  const t = norm(text);

  const anosMatch = t.match(/\b(\d{1,2})\s*anos?\b/);
  if (anosMatch) {
    return {
      idade_anos: String(anosMatch[1]),
      idade_texto: `${anosMatch[1]} anos`
    };
  }

  const mesesMatch = t.match(/\b(\d{1,2})\s*mes(?:es)?\b/);
  if (mesesMatch) {
    return {
      idade_anos: "",
      idade_texto: `${mesesMatch[1]} meses`
    };
  }

  return {
    idade_anos: "",
    idade_texto: ""
  };
}

function extractDogFromStructuredCurrentMessage(text) {
  const original = publicFacingText(text);
  const t = norm(original);

  if (!original) return null;
  if (t.includes("melhoria bruna")) return null;

  const hasAge = /\b\d{1,2}\s*(ano|anos|mes|meses)\b/.test(t);
  const sexo = detectSexFromText(original);
  const castrado = detectCastrationFromText(original);
  const hasSex = sexo === "macho" || sexo === "femea";

  if (!hasAge || !hasSex) return null;

  const parts = original
    .split(",")
    .map(part => publicFacingText(part))
    .filter(Boolean);

  let nome = "";

  if (parts.length >= 2) {
    const first = parts[0] || "";
    const firstNorm = norm(first);

    if (
      first &&
      !/\b\d{1,2}\s*(ano|anos|mes|meses)\b/.test(firstNorm) &&
      !/\b(macho|femea|fêmea)\b/.test(firstNorm) &&
      !/castrad/.test(firstNorm)
    ) {
      nome = titleCaseName(first);
    }
  }

  if (!nome) {
    const firstToken = original
      .split(/[\s,]+/)
      .map(part => publicFacingText(part))
      .filter(Boolean)[0] || "";

    const firstTokenNorm = norm(firstToken);

    if (
      firstToken &&
      !["macho", "femea", "fêmea", "cadela", "cadelinha"].includes(firstTokenNorm) &&
      !/^\d+$/.test(firstTokenNorm)
    ) {
      nome = titleCaseName(firstToken);
    }
  }

  const age = extractAgeFromText(original);

  let raca = "";

  if (parts.length >= 3) {
    const racaCandidate = parts
      .filter(part => {
        const p = norm(part);

        if (!p) return false;
        if (nome && p === norm(nome)) return false;
        if (/\b\d{1,2}\s*(ano|anos|mes|meses)\b/.test(p)) return false;
        if (/\b(macho|femea|fêmea|cadela|cadelinha)\b/.test(p)) return false;
        if (/castrad/.test(p)) return false;

        return true;
      })
      .pop();

    raca = publicFacingText(racaCandidate || "");
  }

  if (!raca) {
    raca = "";
  }

  if (textIsBadBreedAnswer(raca)) {
    raca = "";
  }

  const dog = normalizeDog({
    nome,
    idade_anos: age.idade_anos,
    idade_texto: age.idade_texto,
    raca,
    raca_canonica: "",
    porte: "nao_definido",
    sexo,
    castrado,
    no_cio: sexo === "macho" ? "nao_se_aplica" : "nao_informado",
    vacinas_ok: "nao_informado",
    antipulgas_ok: "nao_informado",
    vermifugacao_ok: "nao_informado",
    perfil_comportamental: "nao_informado",
    comportamento_observacoes: "",
    possui_relatorio_veterinario: age.idade_anos && Number(age.idade_anos) < 10
      ? "nao_se_aplica"
      : "nao_informado",
    observacoes: "",
    regras_raca: {}
  });

  return hasDogIdentity(dog) ? dog : null;
}

function applyCastrationStatusToPatch(caesAtuais = [], caesPatch = [], status = "nao_informado") {
  const patchDogs = normalizeDogs(caesPatch);

  if (patchDogs.length === 1) {
    return patchDogs.map(dog => normalizeDog({
      ...dog,
      castrado: status,
      regras_raca: dog.regras_raca || {}
    }));
  }

  if (patchDogs.length > 1) {
    return patchDogs;
  }

  return buildCastrationStatusPatch(caesAtuais, status);
}

function clearCastrationIntentSignalsForNonAdultMale(turnSignals, dogs = [], warnings = []) {
  const hasAdultMale = hasAdultMaleNonCastrated(dogs);
  const hasFemale = hasFemaleNonCastrated(dogs);

  if (turnSignals.lead_informou_castrado_nao === true && !hasAdultMale) {
    turnSignals.lead_informou_castrado_nao = false;
    turnSignals.lead_pretende_castrar = false;
    turnSignals.lead_nao_pretende_castrar = false;

    warnings.push({
      warning: hasFemale
        ? "femea_nao_castrada_nao_aciona_regra_macho"
        : "castracao_nao_aplicavel_sem_macho_adulto_real",
      motivo: hasFemale
        ? "castracao_de_femea_nao_e_bloqueio_operacional"
        : "MACHO_NAO_CASTRADO_exige_cao_real_macho_com_8_meses_ou_mais_e_castrado_nao"
    });
  }

  if (hasFemale && !hasAdultMale) {
    turnSignals.lead_pretende_castrar = false;
    turnSignals.lead_nao_pretende_castrar = false;
  }

  return turnSignals;
}

function buildTurnSignals(contextSignals = {}, extractorSignals = {}, currentText = "", ctx = {}, dogs = []) {
  const turnContext = getTurnContext(ctx, dogs);

  const priceNow = messageAskedPrice(currentText);
  const priceInsistenceNow = messageIsStrongPriceInsistence(currentText);

  const castradoSimAgora = isCastratedYesText(currentText);
  const castradoNaoAgora = isCastratedNoText(currentText);

  const previousAskedPrice =
    contextSignals.ja_perguntou_preco_antes === true ||
    extractorSignals.ja_perguntou_preco_antes === true;

  const pediuPreco = priceNow || extractorSignals.pediu_preco === true;

  return {
    pediu_preco: pediuPreco,
    insistiu_preco: Boolean(
      priceInsistenceNow ||
      extractorSignals.insistiu_preco === true ||
      (priceNow && previousAskedPrice)
    ),
    ja_perguntou_preco_antes: previousAskedPrice,

    pediu_humano: extractorSignals.pediu_humano === true,
    pediu_localizacao: extractorSignals.pediu_localizacao === true,
    pediu_visita: extractorSignals.pediu_visita === true,
    enviou_comprovante: extractorSignals.enviou_comprovante === true,

    lead_respondeu_dados_cao: extractorSignals.lead_respondeu_dados_cao === true,
    lead_respondeu_sanitario: false,
    lead_respondeu_comportamento: extractorSignals.lead_respondeu_comportamento === true,
    lead_respondeu_frequencia: extractorSignals.lead_respondeu_frequencia === true,
    lead_respondeu_periodo_hotel: extractorSignals.lead_respondeu_periodo_hotel === true,

    lead_confirmou_raca:
      turnContext === "raca" &&
      extractorSignals.lead_confirmou_raca === true,

    lead_confirmou_humano:
      turnContext === "humano" &&
      (
        extractorSignals.lead_confirmou_humano === true ||
        isYesText(currentText)
      ),

    lead_recusou_humano:
      turnContext === "humano" &&
      (
        extractorSignals.lead_recusou_humano === true ||
        isNoText(currentText)
      ),

    lead_finalizou_atendimento:
      turnContext === "finalizacao" &&
      (
        extractorSignals.lead_finalizou_atendimento === true ||
        isFinalThanksText(currentText)
      ),

    lead_pretende_castrar:
      turnContext === "castracao_intencao" &&
      !castradoSimAgora &&
      !castradoNaoAgora &&
      (
        extractorSignals.lead_pretende_castrar === true ||
        isExplicitYesIntentionToCastrate(currentText) ||
        isYesText(currentText)
      ),

    lead_nao_pretende_castrar:
      turnContext === "castracao_intencao" &&
      !castradoSimAgora &&
      !castradoNaoAgora &&
      (
        extractorSignals.lead_nao_pretende_castrar === true ||
        isExplicitNoIntentionToCastrate(currentText) ||
        isNoText(currentText)
      ),

    lead_informou_castrado_sim:
      turnContext === "castracao_status" || castradoSimAgora
        ? castradoSimAgora
        : false,

    lead_informou_castrado_nao:
      turnContext === "castracao_status" || castradoNaoAgora
        ? castradoNaoAgora
        : false
  };
}

const ctx = clone($("Monta Contexto Bruna Solo").first().json);
const extractor = unwrapExtractor($json);

ctx.inputs = ctx.inputs || {};
ctx.inputs.resumo_lead = ctx.inputs.resumo_lead || {};
ctx.inputs.turn_signals = isObject(ctx.inputs.turn_signals) ? ctx.inputs.turn_signals : {};

const caesAtuais = Array.isArray(ctx.inputs.caes_json)
  ? ctx.inputs.caes_json
  : [];

const caesPatchOriginal = Array.isArray(extractor.caes_json)
  ? extractor.caes_json
  : [];

const currentLeadText = publicFacingText(ctx.message?.content || ctx.chatInput || "");
const warnings = [];

const structuredDogFromCurrentMessage = extractDogFromStructuredCurrentMessage(currentLeadText);

if (structuredDogFromCurrentMessage) {
  warnings.push({
    warning: "cao_detectado_deterministicamente_na_mensagem_atual",
    motivo: "mensagem_atual_contem_idade_sexo_e_dados_de_castracao_ou_raca",
    cao_detectado: {
      nome: structuredDogFromCurrentMessage.nome,
      idade_texto: structuredDogFromCurrentMessage.idade_texto,
      sexo: structuredDogFromCurrentMessage.sexo,
      castrado: structuredDogFromCurrentMessage.castrado,
      raca: structuredDogFromCurrentMessage.raca
    }
  });
}

extractor.resumo_lead_patch = isObject(extractor.resumo_lead_patch)
  ? extractor.resumo_lead_patch
  : {};

let turnSignals = buildTurnSignals(
  ctx.inputs.turn_signals,
  isObject(extractor.turn_signals) ? extractor.turn_signals : {},
  currentLeadText,
  ctx,
  caesAtuais
);

const frequencyDetected = normalizeFrequencyText(currentLeadText, ctx);
const hotelPeriodDetected = parseHotelPeriodDays(currentLeadText);

const castradoSimAgora = isCastratedYesText(currentLeadText);
const castradoNaoAgora = isCastratedNoText(currentLeadText);

if (castradoSimAgora) {
  turnSignals.lead_informou_castrado_sim = true;
  turnSignals.lead_informou_castrado_nao = false;
  turnSignals.lead_pretende_castrar = false;
  turnSignals.lead_nao_pretende_castrar = false;
  turnSignals.lead_respondeu_dados_cao = true;
}

if (castradoNaoAgora) {
  turnSignals.lead_informou_castrado_nao = true;
  turnSignals.lead_informou_castrado_sim = false;
  turnSignals.lead_pretende_castrar = false;
  turnSignals.lead_nao_pretende_castrar = false;
  turnSignals.lead_respondeu_dados_cao = true;
}

const currentIsFrequencyOnly = isFrequencyOnlyText(currentLeadText, ctx, caesAtuais);
const currentIsHotelPeriodOnly = isHotelPeriodOnlyText(currentLeadText, caesAtuais);
const currentIsPriceOnly = isPriceOnlyText(currentLeadText);
const currentIsShortOnly = isShortReplyOnly(currentLeadText);

if (frequencyDetected) {
  extractor.resumo_lead_patch.servico_interesse =
    extractor.resumo_lead_patch.servico_interesse || "creche";

  extractor.resumo_lead_patch.periodo_desejado =
    extractor.resumo_lead_patch.periodo_desejado || frequencyDetected;

  turnSignals.lead_respondeu_frequencia = true;
}

if (hotelPeriodDetected) {
  extractor.resumo_lead_patch.servico_interesse = "hotel";
  extractor.resumo_lead_patch.periodo_desejado =
    `período de ${hotelPeriodDetected.start_day} a ${hotelPeriodDetected.end_day}, ${hotelPeriodDetected.diarias} diárias`;

  turnSignals.lead_respondeu_periodo_hotel = true;
}

const isOnlySignalTurn =
  turnSignals.lead_confirmou_humano === true ||
  turnSignals.lead_recusou_humano === true ||
  turnSignals.lead_finalizou_atendimento === true ||
  turnSignals.lead_pretende_castrar === true ||
  turnSignals.lead_nao_pretende_castrar === true ||
  turnSignals.lead_confirmou_raca === true;

const shouldDiscardDogPatch =
  currentIsFrequencyOnly ||
  currentIsHotelPeriodOnly ||
  currentIsPriceOnly ||
  (
    currentIsShortOnly &&
    !dogHasAttributeSignalInText(currentLeadText) &&
    !isBreedConfirmationState(ctx, caesAtuais)
  ) ||
  (
    isOnlySignalTurn &&
    !dogHasAttributeSignalInText(currentLeadText)
  ) ||
  (
    (frequencyDetected || hotelPeriodDetected || turnSignals.pediu_preco === true) &&
    !dogHasAttributeSignalInText(currentLeadText)
  );

let caesPatchSeguro = shouldDiscardDogPatch
  ? []
  : sanitizeBreedFieldsFromExtractor(
      caesPatchOriginal,
      currentLeadText,
      ctx,
      caesAtuais,
      structuredDogFromCurrentMessage
    );

const sanitaryPatch = inferSanitaryFromContext(currentLeadText, ctx, caesAtuais);

if (Object.keys(sanitaryPatch).length) {
  caesPatchSeguro = applySanitaryPatchToDogs(
    caesAtuais,
    caesPatchSeguro,
    sanitaryPatch
  );

  turnSignals.lead_respondeu_sanitario = true;

  warnings.push({
    warning: "sanitario_detectado_por_contexto",
    motivo: "ultima_pergunta_foi_sanitaria_e_resposta_nao_tem_negacao_duvida_ou_rota_comercial"
  });
}

const behaviorPatch = inferBehaviorPatchFromContext(currentLeadText, ctx);

if (Object.keys(behaviorPatch).length) {
  const patchDogs = normalizeDogPatches(caesPatchSeguro);

  if (patchDogs.length) {
    caesPatchSeguro = patchDogs.map(dog => normalizeDog({
      ...dog,
      ...behaviorPatch,
      regras_raca: dog.regras_raca || {}
    }));
  } else if (normalizeDogs(caesAtuais).length === 1) {
    caesPatchSeguro = [behaviorPatch];
  }

  turnSignals.lead_respondeu_comportamento = true;

  warnings.push({
    warning: "comportamento_detectado_por_contexto",
    motivo: "ultima_pergunta_foi_sobre_rotina_ou_convivencia_e_resposta_trouxe_sinal_comportamental"
  });
}

if (structuredDogFromCurrentMessage) {
  caesPatchSeguro = mergeDogs(caesPatchSeguro, [structuredDogFromCurrentMessage]);
}

if (castradoSimAgora) {
  caesPatchSeguro = applyCastrationStatusToPatch(caesAtuais, caesPatchSeguro, "sim");
}

if (castradoNaoAgora) {
  caesPatchSeguro = applyCastrationStatusToPatch(caesAtuais, caesPatchSeguro, "nao");
}

const mustKeepDogPatchBecauseStructuredDog = Boolean(structuredDogFromCurrentMessage);

const caesPatchEfetivo =
  shouldDiscardDogPatch &&
  !castradoSimAgora &&
  !castradoNaoAgora &&
  !mustKeepDogPatchBecauseStructuredDog
    ? []
    : buildBreedConfirmationPatch(ctx, caesAtuais, caesPatchSeguro);

if (caesPatchEfetivo.length > 0) {
  turnSignals.lead_respondeu_dados_cao = true;
}

const caesMesclados = mergeDogs(caesAtuais, caesPatchEfetivo);

clearCastrationIntentSignalsForNonAdultMale(turnSignals, caesMesclados, warnings);

if (castradoSimAgora) {
  warnings.push({
    warning: "castracao_status_confirmado_sim",
    motivo: "lead_informou_que_o_cao_ja_e_castrado_nao_e_intencao_futura",
    lead_pretende_castrar_forcado_false: true,
    lead_nao_pretende_castrar_forcado_false: true
  });
}

if (castradoNaoAgora) {
  warnings.push({
