function norm(value) {
  return String(value ?? "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function clean(value) {
  return String(value ?? "").trim();
}

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function normalizeEnum(value, allowed, fallback) {
  const v = clean(value);
  return allowed.includes(v) ? v : fallback;
}

function hasValue(value) {
  const t = norm(value);
  return Boolean(
    t &&
    ![
      "nao informado",
      "nao_informado",
      "não informado",
      "nao definido",
      "nao_definido",
      "não definido",
      "nao se aplica",
      "nao_se_aplica",
      "não se aplica"
    ].includes(t)
  );
}

function dogName(dog, fallbackIndex = 0) {
