const raw = $input.first().json || {};
const input = Array.isArray(raw) ? (raw[0] || {}) : raw;

function cleanString(value) {
  if (value === undefined || value === null) return "";
  return String(value).trim();
}

function onlyDigits(value) {
  return cleanString(value).replace(/\D/g, "");
}

function firstFilled(...values) {
  for (const value of values) {
    const text = cleanString(value);
    if (text) return text;
  }
  return "";
}

function toBool(value, fallback = false) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1) return true;
  if (value === 0) return false;

  const text = cleanString(value).toLowerCase();

  if (["true", "sim", "yes", "1"].includes(text)) return true;
  if (["false", "nao", "não", "no", "0"].includes(text)) return false;

  return fallback;
}

function safeNumber(value, fallback) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function normalizeArray(value) {
  return Array.isArray(value) ? value : [];
}

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function removeSensitivePixLikeData(obj) {
  if (!isObject(obj)) return {};

  const forbiddenKeys = [
    "pix",
    "chave_pix",
    "chavepix",
    "cnpj",
    "recebedor",
    "banco",
    "agencia",
    "agência",
    "conta",
    "dados_bancarios",
    "dados_bancários"
  ];

  const out = {};

  for (const [key, value] of Object.entries(obj)) {
    const keyNorm = key
      .toLowerCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "");

    if (forbiddenKeys.some(k => keyNorm.includes(k))) {
      continue;
    }

    out[key] = value;
  }

  return out;
}

function normalizePhoneFromSessionId(value) {
  const rawSession = cleanString(value);
  let digits = onlyDigits(rawSession);

  digits = digits.padEnd(18, "0").slice(0, 18);

  return `99${digits}`;
}

function normalizePhone(input) {
  const directPhone = firstFilled(
    input.phone,
    input.telefone,
    input.whatsapp,
    input.lead?.phone,
    input.contact?.phone,
    input.sender?.phone,
    input.body?.phone,
    input.body?.telefone,
    input.body?.whatsapp,
    input.body?.lead?.phone,
    input.metadata?.phone,
    input.metadata?.telefone,
    input.metadata?.whatsapp
  );

  const digits = onlyDigits(directPhone);

  if (digits.length >= 10) {
    return digits;
  }

  return normalizePhoneFromSessionId(
    firstFilled(
      input.sessionId,
      input.body?.sessionId,
      input.chat?.sessionId,
      input.metadata?.sessionId,
      "test-sem-session"
    )
  );
}

function normalizeSessionId(input, phone) {
  return firstFilled(
    input.sessionId,
