    input.chat?.sessionId,
    input.metadata?.sessionId,
    input.chat_history_uuid,
    input.lead?.chat_history_uuid,
    `test-session-${phone}`
  );
}

function normalizeChatInput(input) {
  return firstFilled(
    input.chatInput,
    input.message?.content,
