function parseMaybeJson(value, fallback) {
  if (value === undefined || value === null || value === "") return fallback;
  if (typeof value === "object") return value;

  try {
    return JSON.parse(value);
  } catch (e) {
    const text = String(value || "").trim();
    const match = text.match(/\{[\s\S]*\}/);

    if (match) {
      try {
        return JSON.parse(match[0]);
      } catch (e2) {}
    }

    return fallback;
  }
}

function clone(value) {
  return JSON.parse(JSON.stringify(value || {}));
}

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function normalizeEnum(value, allowed, fallback) {
  const v = String(value || "").trim();
  return allowed.includes(v) ? v : fallback;
}

function toBool(value) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1) return true;
  if (value === 0) return false;

  const text = String(value || "")
    .trim()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");

  if (["1", "true", "sim", "yes", "t"].includes(text)) return true;
  if (["0", "false", "nao", "não", "no", "f"].includes(text)) return false;

  return false;
}

function toNumber(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function cleanText(value) {
  return String(value || "").trim();
}

function cleanArray(value) {
  if (!Array.isArray(value)) return [];
  return value;
}

function compactCandidatas(value) {
  const arr = cleanArray(value);

  return arr
    .filter(item => isObject(item))
    .map(item => ({
      raca_canonica: cleanText(item.raca_canonica),
      score: toNumber(item.score),
      potencial_dano: toBool(item.potencial_dano),
      aceita_auauzin: toBool(item.aceita_auauzin),
      aceita_auauzin_origem: cleanText(item.aceita_auauzin_origem),
      tipo_registro_match: cleanText(item.tipo_registro_match),
      nome_digitado_match: cleanText(item.nome_digitado_match)
    }))
    .filter(item => item.raca_canonica)
    .slice(0, 5);
}

function compactRegrasRaca(value) {
  const regra = isObject(value) ? value : {};

  if (!Object.keys(regra).length) return {};

  let statusRaca = normalizeEnum(
    regra.status_raca,
    [
      "sem_raca_informada",
      "precisa_confirmar_raca",
      "bloqueado_potencial_dano",
      "raca_ok"
    ],
    "sem_raca_informada"
  );

  let decisaoConclusiva = toBool(regra.decisao_raca_conclusiva);
  let precisaConfirmacao = toBool(regra.precisa_confirmacao_antes_decisao);

  if (statusRaca === "raca_ok" && decisaoConclusiva !== true) {
    statusRaca = "precisa_confirmar_raca";
    precisaConfirmacao = true;
  }

  if (statusRaca === "precisa_confirmar_raca") {
    decisaoConclusiva = false;
    precisaConfirmacao = true;
  }

  if (statusRaca === "sem_raca_informada") {
    decisaoConclusiva = false;
    precisaConfirmacao = true;
  }

  return {
    raca_original: cleanText(regra.raca_original),
    raca_canonica: cleanText(regra.raca_canonica),
    raca_canonica_norm: cleanText(regra.raca_canonica_norm),

    porte_classificado: normalizeEnum(
      regra.porte_classificado,
      ["mini", "pequeno", "medio", "grande", "gigante", "nao_definido"],
      "nao_definido"
    ),

    aceita_auauzin: toBool(regra.aceita_auauzin),
    aceita_auauzin_origem: cleanText(regra.aceita_auauzin_origem),

    potencial_dano: toBool(regra.potencial_dano),

    raca_encontrada: toBool(regra.raca_encontrada),
    deve_confirmar_raca: toBool(regra.deve_confirmar_raca),

    status_raca: statusRaca,

    decisao_raca_conclusiva: decisaoConclusiva,
    precisa_confirmacao_antes_decisao: precisaConfirmacao,

    pode_seguir_amaralina_por_raca: toBool(regra.pode_seguir_amaralina_por_raca),
    pode_seguir_auauzin_por_raca: toBool(regra.pode_seguir_auauzin_por_raca),

    motivo_raca: cleanText(regra.motivo_raca),
    escopo_decisao: "por_cao",

    score_match: toNumber(regra.score_match),
    tipo_match: cleanText(regra.tipo_match),
    tipo_registro_match: cleanText(regra.tipo_registro_match),
    nome_digitado_match: cleanText(regra.nome_digitado_match),

    qtd_racas_candidatas: toNumber(regra.qtd_racas_candidatas),
    qtd_matches_mesma_canonica: toNumber(regra.qtd_matches_mesma_canonica),
    qtd_grafias_mesma_canonica: toNumber(regra.qtd_grafias_mesma_canonica),
    total_grafias_canonica: toNumber(regra.total_grafias_canonica),
    possui_linha_canonica: toBool(regra.possui_linha_canonica),

    score_top_1: toNumber(regra.score_top_1),
    score_top_2: toNumber(regra.score_top_2),
    gap_score: toNumber(regra.gap_score),

    nivel_confianca_raca: normalizeEnum(
      regra.nivel_confianca_raca,
      ["sem_raca", "baixa", "media", "alta"],
      ""
    ),

    racas_candidatas: compactCandidatas(regra.racas_candidatas)
  };
}

function normalizeDog(dog = {}) {
  const regra = compactRegrasRaca(dog.regras_raca);

  const statusRaca = regra.status_raca || "";
  const decisaoConclusiva = regra.decisao_raca_conclusiva === true;

  const shouldApplyCanonicalBreed =
    regra.raca_encontrada === true &&
    decisaoConclusiva === true &&
    statusRaca !== "precisa_confirmar_raca" &&
    statusRaca !== "sem_raca_informada";

  const shouldApplyBreedPorte =
    shouldApplyCanonicalBreed &&
    regra.porte_classificado &&
    regra.porte_classificado !== "nao_definido";

  const basePorte = normalizeEnum(
    dog.porte,
    ["mini", "pequeno", "medio", "grande", "gigante", "nao_definido"],
    "nao_definido"
  );

  const sexo = normalizeEnum(
    dog.sexo,
    ["macho", "femea", "nao_informado"],
    "nao_informado"
  );

  return {
    nome: cleanText(dog.nome),
    idade_anos: cleanText(dog.idade_anos),
    idade_texto: cleanText(dog.idade_texto),
    raca: cleanText(dog.raca),

    raca_canonica: shouldApplyCanonicalBreed
      ? cleanText(regra.raca_canonica)
      : cleanText(dog.raca_canonica),

    porte: shouldApplyBreedPorte
      ? regra.porte_classificado
      : basePorte,

    sexo,

    castrado: normalizeEnum(
      dog.castrado,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    no_cio: sexo === "macho"
      ? "nao_se_aplica"
      : normalizeEnum(
          dog.no_cio,
          ["sim", "nao", "nao_se_aplica", "nao_informado"],
          "nao_informado"
        ),

    vacinas_ok: normalizeEnum(
      dog.vacinas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    antipulgas_ok: normalizeEnum(
      dog.antipulgas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    vermifugacao_ok: normalizeEnum(
      dog.vermifugacao_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    perfil_comportamental: normalizeEnum(
      dog.perfil_comportamental,
      [
        "nao_informado",
        "tranquilo",
        "sociavel",
        "seletivo",
        "reativo_leve",
        "reativo_alto",
        "agressivo",
        "indeterminado"
      ],
      "nao_informado"
    ),

    comportamento_observacoes: cleanText(dog.comportamento_observacoes),

    possui_relatorio_veterinario: normalizeEnum(
      dog.possui_relatorio_veterinario,
      ["sim", "nao", "nao_se_aplica", "nao_informado"],
      "nao_informado"
    ),

    observacoes: cleanText(dog.observacoes),

    regras_raca: regra
  };
}

function stripDogDuplicates(ctx) {
  delete ctx.caes_json;
  delete ctx.regras_raca;
  delete ctx.consulta_raca_payload;

  if (ctx.memory) {
    delete ctx.memory.caes_json;
    delete ctx.memory.quantidade_caes;
    delete ctx.memory.resumo_lead_json;
    delete ctx.memory.resumo_interno_repasse_json;
    delete ctx.memory.payload_ultima_resposta_json;
  }

  if (ctx.inputs?.resumo_lead) {
    delete ctx.inputs.resumo_lead.caes_json;
    delete ctx.inputs.resumo_lead.quantidade_caes;
  }

  if (ctx.inputs?.resumo_interno_repasse) {
    delete ctx.inputs.resumo_interno_repasse.caes_json;
    delete ctx.inputs.resumo_interno_repasse.quantidade_caes;
  }

  return ctx;
}

const ctx = clone($("Normaliza Extrator e Prepara Raças").first().json);

const resultadoConsulta = parseMaybeJson($json.regras_raca, {
  caes_json: [],
  total_caes_consultados: 0,
  formato: "inputs.caes_json[].regras_raca"
});

const caesComRegras = Array.isArray(resultadoConsulta.caes_json)
  ? resultadoConsulta.caes_json
  : [];

const regrasPorIndex = new Map(
  caesComRegras.map((dog, index) => {
    const regra = isObject(dog.regras_raca) ? dog.regras_raca : {};
    const dogIndex = Number.isFinite(Number(regra.dog_index))
      ? Number(regra.dog_index)
      : index;

    return [dogIndex, dog];
  })
);

const caesOriginais = Array.isArray(ctx.inputs?.caes_json)
  ? ctx.inputs.caes_json
  : [];

const caesJson = caesOriginais.map((dog, index) => {
  const base = normalizeDog(dog);
  const enriquecido = regrasPorIndex.get(index);

  if (!enriquecido) return base;

  const regra = compactRegrasRaca(enriquecido.regras_raca);

