const raw = $input.first().json || {};
const NORMALIZA_BRUNA_VERSION = "v16_guard_atual_sem_override_antigo";

function getNodeJson(nodeName) {
  try {
    return $(nodeName).first().json || {};
  } catch (e) {
    return {};
  }
}

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function isNonEmptyObject(value) {
  return isObject(value) && Object.keys(value).length > 0;
}

function firstObject(...values) {
  for (const value of values) {
    if (isNonEmptyObject(value)) return value;
  }
  return {};
}

function clean(value) {
  if (value === undefined || value === null) return "";

  if (typeof value === "object") {
    try {
      return JSON.stringify(value);
    } catch (e) {
      return "";
    }
  }

  return String(value).trim();
}

function norm(value) {
  return clean(value)
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function toBool(value) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1) return true;
  if (value === 0) return false;

  const t = norm(value);

  if (["1", "true", "sim", "yes", "s"].includes(t)) return true;
  if (["0", "false", "nao", "não", "no", "n"].includes(t)) return false;

  return false;
}

function parseJsonFlexible(value) {
  if (value === undefined || value === null) return {};

  if (typeof value === "object") return value;

  let text = String(value || "").trim();

  text = text
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();

  const firstBrace = text.indexOf("{");
  const lastBrace = text.lastIndexOf("}");

  if (firstBrace >= 0 && lastBrace > firstBrace) {
    text = text.slice(firstBrace, lastBrace + 1);
  }

  try {
    return JSON.parse(text);
  } catch (error) {
    return {
      __parse_error: true,
      __parse_error_message: error.message,
      __raw_text: value
    };
  }
}

function unwrapBrunaOutput(value) {
  const parsed = parseJsonFlexible(value);

  if (!isObject(parsed)) {
    return {
      bruna: {},
      parse_error: true,
      raw_parsed: parsed
    };
  }

  if (parsed.__parse_error === true) {
    return {
      bruna: parsed,
      parse_error: true,
      raw_parsed: parsed
    };
  }

  if (typeof parsed.output === "string") {
    const nested = parseJsonFlexible(parsed.output);

    if (nested.__parse_error === true) {
      return {
        bruna: nested,
        parse_error: true,
        raw_parsed: parsed
      };
    }

    if (isObject(nested)) {
      const merged = {
        ...parsed,
        ...nested
      };

      delete merged.output;

      return {
        bruna: merged,
        parse_error: false,
        raw_parsed: parsed
      };
    }
  }

  if (isObject(parsed.output)) {
    const merged = {
      ...parsed,
      ...parsed.output
    };

    delete merged.output;

    return {
      bruna: merged,
      parse_error: false,
      raw_parsed: parsed
    };
  }

  for (const key of ["text", "response", "chatOutput"]) {
    if (typeof parsed[key] === "string") {
      const nested = parseJsonFlexible(parsed[key]);

      if (!nested.__parse_error && isObject(nested)) {
        const merged = {
          ...parsed,
          ...nested
        };

        delete merged[key];

        return {
          bruna: merged,
          parse_error: false,
          raw_parsed: parsed
        };
      }
    }
  }

  return {
    bruna: parsed,
    parse_error: false,
    raw_parsed: parsed
  };
}

function parseArray(value) {
  if (Array.isArray(value)) return value;

  if (typeof value === "string" && value.trim()) {
    try {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      return [];
    }
  }

  return [];
}

function enumValue(value, allowed, fallback, warnings, path = "") {
  const v = clean(value);

  if (allowed.includes(v)) return v;

  if (v && path) {
    warnings.push({
      path,
      raw: v,
      result: fallback,
      reason: "enum_invalido_usado_fallback"
    });
  }

  return fallback;
}

function firstFilled(...values) {
  for (const value of values) {
    const v = clean(value);
    if (v !== "") return v;
  }

  return "";
}

function normalizeMessages(value) {
  const arr = Array.isArray(value) ? value : [];

  return arr
    .map(clean)
    .filter(Boolean)
    .slice(0, 4);
}

function hasValue(value) {
  const t = norm(value);

  return Boolean(
    t &&
    ![
      "nao informado",
      "nao_informado",
      "não informado",
      "nao definido",
      "nao_definido",
      "não definido",
      "nao se aplica",
      "nao_se_aplica",
      "não se aplica"
    ].includes(t)
  );
}

function normalizeDog(dog = {}) {
  const out = {
    nome: clean(dog.nome),
    idade_anos: clean(dog.idade_anos),
    idade_texto: clean(dog.idade_texto),
    raca: clean(dog.raca),
    raca_canonica: clean(dog.raca_canonica),

    porte: ["mini", "pequeno", "medio", "grande", "gigante", "nao_definido"].includes(clean(dog.porte))
      ? clean(dog.porte)
      : "nao_definido",

    sexo: ["macho", "femea", "nao_informado"].includes(clean(dog.sexo))
      ? clean(dog.sexo)
      : "nao_informado",

    castrado: ["sim", "nao", "nao_informado"].includes(clean(dog.castrado))
      ? clean(dog.castrado)
      : "nao_informado",

    no_cio: ["sim", "nao", "nao_se_aplica", "nao_informado"].includes(clean(dog.no_cio))
      ? clean(dog.no_cio)
      : "nao_informado",

    vacinas_ok: ["sim", "nao", "nao_informado"].includes(clean(dog.vacinas_ok))
      ? clean(dog.vacinas_ok)
      : "nao_informado",

    antipulgas_ok: ["sim", "nao", "nao_informado"].includes(clean(dog.antipulgas_ok))
      ? clean(dog.antipulgas_ok)
      : "nao_informado",

    vermifugacao_ok: ["sim", "nao", "nao_informado"].includes(clean(dog.vermifugacao_ok))
      ? clean(dog.vermifugacao_ok)
      : "nao_informado",

    perfil_comportamental: [
      "nao_informado",
      "sociavel",
      "seletivo",
      "reativo_leve",
      "reativo_alto",
      "agressivo",
      "indeterminado",
      "tranquilo"
    ].includes(clean(dog.perfil_comportamental))
      ? clean(dog.perfil_comportamental)
      : "nao_informado",

    comportamento_observacoes: clean(dog.comportamento_observacoes),

    possui_relatorio_veterinario: [
      "sim",
      "nao",
      "nao_se_aplica",
      "nao_informado"
    ].includes(clean(dog.possui_relatorio_veterinario))
      ? clean(dog.possui_relatorio_veterinario)
      : "nao_informado",

    observacoes: clean(dog.observacoes),
    regras_raca: isObject(dog.regras_raca) ? dog.regras_raca : {}
  };

  if (out.sexo === "macho") {
    out.no_cio = "nao_se_aplica";
  }

  return out;
}

function isRealDog(dog = {}) {
  const d = normalizeDog(dog);

  return (
    hasValue(d.nome) ||
    hasValue(d.idade_anos) ||
    hasValue(d.idade_texto) ||
    hasValue(d.raca) ||
    hasValue(d.raca_canonica) ||
    ["macho", "femea"].includes(d.sexo)
  );
}

function ageMonths(dog = {}) {
  const idadeTexto = norm(dog.idade_texto);
  const idadeAnos = clean(dog.idade_anos);

  const mesesMatch = idadeTexto.match(/(\d{1,2})\s*(mes|meses)/);
  if (mesesMatch) return Number(mesesMatch[1]);

  const anosMatch = idadeTexto.match(/(\d{1,2})\s*(ano|anos)/);
  if (anosMatch) return Number(anosMatch[1]) * 12;

  if (/^\d+$/.test(idadeAnos)) return Number(idadeAnos) * 12;

  return null;
}

function isMaleAdult(dog = {}) {
  const months = ageMonths(dog);
  return dog.sexo === "macho" && months !== null && months >= 8;
}

function basicComplete(dog = {}) {
  return (
    hasValue(dog.nome) &&
    (hasValue(dog.idade_anos) || hasValue(dog.idade_texto)) &&
    hasValue(dog.raca) &&
    ["macho", "femea"].includes(dog.sexo)
  );
}

function sanitaryComplete(dog = {}) {
  return (
    dog.vacinas_ok === "sim" &&
    dog.antipulgas_ok === "sim" &&
    dog.vermifugacao_ok === "sim"
  );
}

function behaviorComplete(dog = {}) {
  return (
    dog.perfil_comportamental !== "nao_informado" ||
    hasValue(dog.comportamento_observacoes)
  );
}

function raceStatus(dog = {}) {
  return clean(dog.regras_raca?.status_raca || "sem_raca_informada");
}

function raceConclusive(dog = {}) {
  return dog.regras_raca?.decisao_raca_conclusiva === true;
}

function dogName(dog = {}, index = 0) {
  const nome = clean(dog.nome);
  return nome || `cão ${index + 1}`;
}

function stripDogCopies(obj = {}) {
  const out = { ...(isObject(obj) ? obj : {}) };

  delete out.caes_json;
  delete out.quantidade_caes;
  delete out.regras_raca;

  delete out.caes;
  delete out.cao_nome;
  delete out.cao_idade_anos;
  delete out.cao_idade_texto;
  delete out.cao_raca;
  delete out.cao_porte;
  delete out.cao_sexo;
  delete out.cao_castrado;
  delete out.cao_no_cio;
  delete out.cao_vacinas_ok;
  delete out.cao_antipulgas_ok;
  delete out.cao_vermifugacao_ok;
  delete out.cao_perfil_comportamental;
  delete out.cao_comportamento_observacoes;
  delete out.possui_relatorio_veterinario;

  return out;
}

