function parseMaybeJson(value, fallback) {
  if (value === undefined || value === null || value === "") return fallback;
  if (typeof value === "object") return value;

  const text = String(value || "")
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();

  try {
    return JSON.parse(text);
  } catch (e) {
    const arrayMatch = text.match(/\[[\s\S]*\]/);
    if (arrayMatch) {
      try {
        return JSON.parse(arrayMatch[0]);
      } catch (e2) {}
    }

    const objectMatch = text.match(/\{[\s\S]*\}/);
    if (objectMatch) {
      try {
        return JSON.parse(objectMatch[0]);
      } catch (e3) {}
    }
  }

  return fallback;
}

function clone(value) {
  return JSON.parse(JSON.stringify(value || {}));
}

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function cleanText(value) {
  return String(value || "").trim();
}

function publicFacingText(value) {
  return cleanText(value)
    .replace(/\s{2,}/g, " ")
    .trim();
}

function norm(value) {
  return publicFacingText(value)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizeEnum(value, allowed, fallback) {
  const v = cleanText(value);
  return allowed.includes(v) ? v : fallback;
}

function meaningful(value) {
  const v = norm(value);

  return Boolean(
    v &&
    ![
      "nao_informado",
      "nao informado",
      "não informado",
      "nao_definido",
      "nao definido",
      "não definido",
      "nao_se_aplica",
      "nao se aplica",
      "não se aplica",
      "indefinido"
    ].includes(v)
  );
}

function dogPatchHasComplementaryData(dog = {}) {
  if (!isObject(dog)) return false;

  return Boolean(
    ["sim", "nao"].includes(cleanText(dog.vacinas_ok)) ||
    ["sim", "nao"].includes(cleanText(dog.antipulgas_ok)) ||
    ["sim", "nao"].includes(cleanText(dog.vermifugacao_ok)) ||
    ["tranquilo", "sociavel", "seletivo", "reativo_leve", "reativo_alto", "agressivo", "indeterminado"].includes(cleanText(dog.perfil_comportamental)) || cleanText(dog.comportamento_observacoes) ||
    ["sim", "nao"].includes(cleanText(dog.castrado)) ||
    ["sim", "nao"].includes(cleanText(dog.no_cio)) ||
    ["sim", "nao"].includes(cleanText(dog.possui_relatorio_veterinario))
  );
}

