function norm(value) {
  return String(value ?? "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function clean(value) {
  return String(value ?? "").trim();
}

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function normalizeEnum(value, allowed, fallback) {
  const v = clean(value);
  return allowed.includes(v) ? v : fallback;
}

function hasValue(value) {
  const t = norm(value);
  return Boolean(
    t &&
    ![
      "nao informado",
      "nao_informado",
      "não informado",
      "nao definido",
      "nao_definido",
      "não definido",
      "nao se aplica",
      "nao_se_aplica",
      "não se aplica"
    ].includes(t)
  );
}

function dogName(dog, fallbackIndex = 0) {
  const name = clean(dog?.nome);
  if (name) return name;
  return `cão ${fallbackIndex + 1}`;
}

function normalizeDog(dog = {}) {
  const out = {
    nome: clean(dog.nome),
    idade_anos: clean(dog.idade_anos),
    idade_texto: clean(dog.idade_texto),
    raca: clean(dog.raca),
    raca_canonica: clean(dog.raca_canonica),

    porte: normalizeEnum(
      dog.porte,
      ["mini", "pequeno", "medio", "grande", "gigante", "nao_definido"],
      "nao_definido"
    ),

    sexo: normalizeEnum(
      dog.sexo,
      ["macho", "femea", "nao_informado"],
      "nao_informado"
    ),

    castrado: normalizeEnum(
      dog.castrado,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    no_cio: normalizeEnum(
      dog.no_cio,
      ["sim", "nao", "nao_se_aplica", "nao_informado"],
      "nao_informado"
    ),

    vacinas_ok: normalizeEnum(
      dog.vacinas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    antipulgas_ok: normalizeEnum(
      dog.antipulgas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    vermifugacao_ok: normalizeEnum(
      dog.vermifugacao_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    perfil_comportamental: normalizeEnum(
      dog.perfil_comportamental,
      [
        "nao_informado",
        "sociavel",
        "seletivo",
        "reativo_leve",
        "reativo_alto",
        "agressivo",
        "indeterminado",
        "tranquilo"
      ],
      "nao_informado"
    ),

    comportamento_observacoes: clean(dog.comportamento_observacoes),

    possui_relatorio_veterinario: normalizeEnum(
      dog.possui_relatorio_veterinario,
      ["sim", "nao", "nao_se_aplica", "nao_informado"],
      "nao_informado"
    ),

    observacoes: clean(dog.observacoes),
    regras_raca: isObject(dog.regras_raca) ? dog.regras_raca : {}
  };

  if (out.sexo === "macho") {
    out.no_cio = "nao_se_aplica";
  }

  return out;
}

function isRealDog(dog = {}) {
  const d = normalizeDog(dog);

  return (
    hasValue(d.nome) ||
    hasValue(d.idade_anos) ||
    hasValue(d.idade_texto) ||
    hasValue(d.raca) ||
    hasValue(d.raca_canonica) ||
    ["macho", "femea"].includes(d.sexo)
  );
}

function getDogs() {
