}

function ageMonths(dog = {}) {
  const idadeTexto = norm(dog.idade_texto);
  const idadeAnos = clean(dog.idade_anos);

  const mesesMatch = idadeTexto.match(/(\d{1,2})\s*(mes|meses)/);
  if (mesesMatch) {
    return Number(mesesMatch[1]);
  }

  const anosMatchTexto = idadeTexto.match(/(\d{1,2})\s*(ano|anos)/);
  if (anosMatchTexto) {
    return Number(anosMatchTexto[1]) * 12;
  }

  if (/^\d+$/.test(idadeAnos)) {
    return Number(idadeAnos) * 12;
  }

  return null;
}

function isMaleAdult(dog = {}) {
  const months = ageMonths(dog);
  return dog.sexo === "macho" && months !== null && months >= 8;
