}

function hasBlockedRace(dogs = []) {
  return dogs.some(dog => raceStatus(dog) === "bloqueado_potencial_dano");
}

function allDogsBlockedByRace(dogs = []) {
  if (!dogs.length) return false;
  return dogs.every(dog => raceStatus(dog) === "bloqueado_potencial_dano");
}

function hasAnyDogOkOrPending(dogs = []) {
  return dogs.some(dog => {
    const status = raceStatus(dog);

    return (
      status === "raca_ok" ||
      status === "sem_raca_informada" ||
      status === "precisa_confirmar_raca"
    );
  });
}

function raceNeedsPriority(dogs = []) {
  return hasPendingRace(dogs) || hasBlockedRace(dogs);
