function isSimpleYes(text) {
  const t = norm(text);
  return /^(sim|s|isso|isso mesmo|correto|certo|exato|confirmo|positivo|pretendo|vou castrar|quero castrar)$/.test(t);
}

function isSimpleNo(text) {
  const t = norm(text);
  return /^(nao|não|n|negativo|nao pretendo|não pretendo|nao vou|não vou)$/.test(t);
}

function saysWillCastrate(text) {
  const t = norm(text);

  return (
    isSimpleYes(text) ||
    /(pretendo|vou|quero|penso em|estou vendo|irei|vamos)\s+castrar/.test(t) ||
    /castrar\s+(sim|vou|pretendo)/.test(t)
