  if (!basicComplete(dog)) return `perguntar_dados_basicos_do_${name}`;

  if (raceStatus(dog) === "sem_raca_informada" || raceStatus(dog) === "precisa_confirmar_raca") {
    return `aguardar_confirmacao_raca`;
  }

  if (dog.sexo === "femea" && dog.no_cio === "nao_informado") {
    return `perguntar_se_esta_no_cio_da_${name}`;
  }

  if (isMaleAdult(dog) && dog.castrado === "nao_informado") {
    return "aguardar_confirmacao_castracao_status";
  }

  if (!behaviorComplete(dog)) return `perguntar_comportamento_em_grupo_do_${name}`;

  if (!sanitaryComplete(dog)) return `perguntar_dados_sanitarios_do_${name}`;

  return "explicar_avaliacao_e_repassar_para_humano";
}

